  ('lib.lead.lead_stale_after_7_days', 'lead', 'agent', 'follow_up_required', 'לידים: פער בטיפול בהליד (7 יום)', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'הליד מציג פער (ליד מיושן אחרי 7 ימים) שמעכב התקדמות אפקטיבית — כבר 7 יחידות זמן. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'לידים: פער בטיפול בהליד (7 יום)', 'השלם את החסר בהליד (ליד מיושן אחרי 7 ימים) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהליד (ליד מיושן אחרי 7 ימים) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהליד. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־9,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והליד חוזר למסלול טיפול פעיל.', 'לידים: ליד מיושן אחרי 7 ימים. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והליד חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (לידים/ליד מיושן אחרי 7 ימים) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.lead.lead_no_owner', 'lead', 'agent', 'follow_up_required', 'לידים: פער בטיפול בהליד (וריאנט 4)', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'הליד מציג פער (ליד ללא בעלים) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'לידים: פער בטיפול בהליד (וריאנט 4)', 'השלם את החסר בהליד (ליד ללא בעלים) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהליד (ליד ללא בעלים) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהליד. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־9,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והליד חוזר למסלול טיפול פעיל.', 'לידים: ליד ללא בעלים. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והליד חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (לידים/ליד ללא בעלים) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.lead.duplicate_lead_suspected', 'lead', 'agent', 'manager_review', 'לידים: בעיית איכות נתונים', 'זוהתה בעיית איכות נתונים שמשבשת החלטות.', 'זוהתה בעיית איכות נתונים שמשבשת החלטות.', 'זוהתה בעיית איכות נתונים/מערכת (כפילות ליד חשד). נתונים שגויים פוגעים באמינות ההמלצות והדוחות. מומלץ לטפל בשורש הבעיה כדי לשמור על דיוק ההחלטות בכל המערכת.', 'לידים: בעיית איכות נתונים', 'טפל בבעיית הנתונים (כפילות ליד חשד) או הסלם לגורם המתאים כדי לשמור על דיוק.', 'טפל בבעיית הנתונים (כפילות ליד חשד) או הסלם לגורם המתאים כדי לשמור על דיוק.', 'קיימת בעיית איכות נתונים (כפילות ליד חשד). ודא טיפול כדי לשמר אמינות החלטות ודוחות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־9,000 ₪ בעסקה ממוצעת מסוג זה.', 'נתונים שגויים מתפשטים ופוגעים בכל שכבת ההחלטה.', 'איכות הנתונים משוחזרת והדיוק נשמר.', 'לידים: כפילות ליד חשד. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'איכות הנתונים משוחזרת והדיוק נשמר.', null, null, null, 'אוטומציה (לידים/כפילות ליד חשד) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.lead.lead_matches_active_property', 'lead', 'agent', 'growth_opportunity', 'לידים: הליד מחובר להזדמנות נוספת (וריאנט 3)', 'הליד מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'הליד מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'הליד מחובר להקשר נוסף במערכת (ליד תואם פעיל נכס). חיבורים חוצי-מודולים הם מקור יתרון: הם חושפים הזדמנות או מסלול פעולה שלא נראה במבט נקודתי. מומלץ לבחון את הקשר ולפעול למימוש הערך המשולב.', 'לידים: הליד מחובר להזדמנות נוספת (וריאנט 3)', 'נצל את החיבור של הליד (ליד תואם פעיל נכס) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'נצל את החיבור של הליד (ליד תואם פעיל נכס) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'הליד מחובר להזדמנות נוספת. ודא שהקשר מנוצל ולא נופל בין הכיסאות.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־9,000 ₪ בעסקה ממוצעת.', 'חיבורים חוצי-מודולים מתפוגגים אם לא פועלים עליהם בזמן.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', 'לידים: ליד תואם פעיל נכס. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', null, null, null, 'אוטומציה (לידים/ליד תואם פעיל נכס) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
