  ('lib.buyer.buyer_no_contact_7_days', 'buyer', 'agent', 'follow_up_required', 'קונים: פער בטיפול בהקונה (7 יום)', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'הקונה מציג פער (קונה ללא יצירת קשר 7 ימים) שמעכב התקדמות אפקטיבית — כבר 7 יחידות זמן. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'קונים: פער בטיפול בהקונה (7 יום)', 'השלם את החסר בהקונה (קונה ללא יצירת קשר 7 ימים) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהקונה (קונה ללא יצירת קשר 7 ימים) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהקונה. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־14,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והקונה חוזר למסלול טיפול פעיל.', 'קונים: קונה ללא יצירת קשר 7 ימים. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והקונה חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (קונים/קונה ללא יצירת קשר 7 ימים) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.buyer.buyer_no_contact_14_days', 'buyer', 'agent', 'follow_up_required', 'קונים: פער בטיפול בהקונה (14 יום)', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'הקונה מציג פער (קונה ללא יצירת קשר 14 ימים) שמעכב התקדמות אפקטיבית — כבר 14 יחידות זמן. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'קונים: פער בטיפול בהקונה (14 יום)', 'השלם את החסר בהקונה (קונה ללא יצירת קשר 14 ימים) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהקונה (קונה ללא יצירת קשר 14 ימים) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהקונה. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־14,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והקונה חוזר למסלול טיפול פעיל.', 'קונים: קונה ללא יצירת קשר 14 ימים. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והקונה חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (קונים/קונה ללא יצירת קשר 14 ימים) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.buyer.buyer_missed_viewing', 'buyer', 'agent', 'deal_risk', 'קונים: סיכון פעיל בהקונה (וריאנט 2)', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'הקונה נמצא בסיכון (קונה הוחמץ צפייה בנכס). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'קונים: סיכון פעיל בהקונה (וריאנט 2)', 'טפל בשורש הסיכון בהקונה (קונה הוחמץ צפייה בנכס) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בהקונה (קונה הוחמץ צפייה בנכס) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'הקונה בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־14,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'קונים: קונה הוחמץ צפייה בנכס. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (קונים/קונה הוחמץ צפייה בנכס) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.buyer.buyer_completed_viewing', 'buyer', 'agent', 'growth_opportunity', 'קונים: התקדמות חיובית למינוף', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'הקונה עבר אבן דרך חיובית (קונה הושלם צפייה בנכס). רגעי הצלחה הם הזדמנות למינוף: בקשת המלצה, הפניה או הרחבת קשר. מומלץ לתעד, לחזק את הקשר ולבחון צעד מנוף.', 'קונים: התקדמות חיובית למינוף', 'נצל את ההצלחה בהקונה: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'נצל את ההצלחה בהקונה: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'הקונה רשם הצלחה. ודא תיעוד ומינוף (המלצה/הפניה/סיפור הצלחה) להגדלת ערך.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־14,000 ₪ בעסקה ממוצעת.', 'חלון המינוף לאחר הצלחה קצר — מומלץ לפעול בסמוך לאירוע.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', 'קונים: קונה הושלם צפייה בנכס. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא קונה הושלם צפייה בנכס. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', 'עדכון אישי בפורטל: הכנו עבורך מידע ממוקד בנושא קונה הושלם צפייה בנכס. הסוכן/ת שלך זמין/ה להמשך.', null, 'אוטומציה (קונים/קונה הושלם צפייה בנכס) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.buyer.buyer_objection_added', 'buyer', 'agent', 'quick_win', 'קונים: הקונה חדש נכנס למערכת (וריאנט 2)', 'הקונה נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הקונה נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הקונה נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון. (וריאנט 2)', 'קונים: הקונה חדש נכנס למערכת (וריאנט 2)', 'הקונה חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'הקונה חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט הקונה חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־14,000 ₪ בעסקה ממוצעת.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'הקונה מטופל, משויך ומקודם לצעד הבא במסלול.', 'קונים: קונה התנגדות נוסף. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הקונה מטופל, משויך ומקודם לצעד הבא במסלול.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא קונה התנגדות נוסף. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (קונים/קונה התנגדות נוסף) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.buyer.buyer_objection_unresolved', 'buyer', 'agent', 'deal_risk', 'קונים: סיכון פעיל בהקונה (וריאנט 3)', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'הקונה נמצא בסיכון (קונה התנגדות לא נפתר). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'קונים: סיכון פעיל בהקונה (וריאנט 3)', 'טפל בשורש הסיכון בהקונה (קונה התנגדות לא נפתר) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בהקונה (קונה התנגדות לא נפתר) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'הקונה בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־14,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'קונים: קונה התנגדות לא נפתר. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (קונים/קונה התנגדות לא נפתר) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.buyer.buyer_commitment_broken', 'buyer', 'agent', 'customer_risk', 'קונים: אירוע שדורש סגירה מסודרת (וריאנט 2)', 'זוהה אירוע שלילי שדורש סגירה מסודרת או הצלה.', 'זוהה אירוע שלילי שדורש סגירה מסודרת או הצלה.', 'הקונה עבר אירוע שלילי (קונה התחייבות הופרה). חשוב לסגור מסודר, ללמוד את הסיבה, ולבחון אם יש מסלול הצלה. טיפול נכון גם באירוע שלילי שומר על מוניטין ועל פוטנציאל עתידי.', 'קונים: אירוע שדורש סגירה מסודרת (וריאנט 2)', 'סגור מסודר את הקונה, תעד את הסיבה, ובחן אם קיים מסלול הצלה או חידוש קשר עתידי.', 'סגור מסודר את הקונה, תעד את הסיבה, ובחן אם קיים מסלול הצלה או חידוש קשר עתידי.', 'הקונה ברצף שלילי. ודא סגירה מסודרת ולמידה לשימור איכות התהליך.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־14,000 ₪ בעסקה ממוצעת מסוג זה.', 'סגירה לא מסודרת פוגעת בנתונים ובמוניטין.', 'האירוע נסגר מסודר, מתועד, ונבחנת אפשרות הצלה.', 'קונים: קונה התחייבות הופרה. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'האירוע נסגר מסודר, מתועד, ונבחנת אפשרות הצלה.', null, null, null, 'אוטומציה (קונים/קונה התחייבות הופרה) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.buyer.buyer_commitment_fulfilled', 'buyer', 'agent', 'growth_opportunity', 'קונים: התקדמות חיובית למינוף (וריאנט 2)', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'הקונה עבר אבן דרך חיובית (קונה התחייבות מומשה). רגעי הצלחה הם הזדמנות למינוף: בקשת המלצה, הפניה או הרחבת קשר. מומלץ לתעד, לחזק את הקשר ולבחון צעד מנוף.', 'קונים: התקדמות חיובית למינוף (וריאנט 2)', 'נצל את ההצלחה בהקונה: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'נצל את ההצלחה בהקונה: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'הקונה רשם הצלחה. ודא תיעוד ומינוף (המלצה/הפניה/סיפור הצלחה) להגדלת ערך.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־14,000 ₪ בעסקה ממוצעת.', 'חלון המינוף לאחר הצלחה קצר — מומלץ לפעול בסמוך לאירוע.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', 'קונים: קונה התחייבות מומשה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא קונה התחייבות מומשה. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', 'עדכון אישי בפורטל: הכנו עבורך מידע ממוקד בנושא קונה התחייבות מומשה. הסוכן/ת שלך זמין/ה להמשך.', null, 'אוטומציה (קונים/קונה התחייבות מומשה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.buyer.buyer_moved_journey_stage', 'buyer', 'agent', 'high_priority', 'קונים: קונה עבר מסע שלב', 'זוהה אירוע בקונים שמצדיק פעולה יזומה.', 'זוהה אירוע בקונים שמצדיק פעולה יזומה.', 'זוהה אירוע בקונים (קונה עבר מסע שלב) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'קונים: קונה עבר מסע שלב', 'בחן את ההקשר של קונה עבר מסע שלב בהקונה, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של קונה עבר מסע שלב בהקונה, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בקונים (קונה עבר מסע שלב) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־14,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'קונים: קונה עבר מסע שלב. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (קונים/קונה עבר מסע שלב) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
