  ('lib.buyer.buyer_portal_viewed', 'buyer', 'agent', 'customer_risk', 'קונים: הקונה גילה מעורבות פעילה (וריאנט 6)', 'הקונה גילה מעורבות פעילה — הרגע הנכון להמשך יזום.', 'הקונה גילה מעורבות פעילה — הרגע הנכון להמשך יזום.', 'הקונה ביצע פעולת מעורבות (קונה פורטל נצפה). מעורבות יזומה היא אות חם: הלקוח עוסק באופן פעיל. מומלץ לנצל את המומנטום בפנייה רלוונטית שממשיכה בדיוק מהנקודה שבה הוא התעניין.', 'קונים: הקונה גילה מעורבות פעילה (וריאנט 6)', 'הקונה מעורב עכשיו — פנה בהקשר למה שצפה/לחץ, והצע צעד המשך טבעי (פרטים, סיור או שיחה).', 'הקונה מעורב עכשיו — פנה בהקשר למה שצפה/לחץ, והצע צעד המשך טבעי (פרטים, סיור או שיחה).', 'זוהתה מעורבות פעילה של הקונה. ודא מענה מהיר כדי להמיר עניין לפעולה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־14,000 ₪ בעסקה ממוצעת.', 'מענה תוך זמן קצר ממעורבות מגדיל מהותית את סיכויי ההמרה.', 'המעורבות מנוצלת ומומרת לצעד התקדמות מוחשי.', 'קונים: קונה פורטל נצפה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'המעורבות מנוצלת ומומרת לצעד התקדמות מוחשי.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא קונה פורטל נצפה. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', 'עדכון אישי בפורטל: הכנו עבורך מידע ממוקד בנושא קונה פורטל נצפה. הסוכן/ת שלך זמין/ה להמשך.', null, 'אוטומציה (קונים/קונה פורטל נצפה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.buyer.buyer_portal_not_viewed', 'buyer', 'agent', 'follow_up_required', 'קונים: פער בטיפול בהקונה (וריאנט 5)', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'הקונה מציג פער (קונה פורטל לא נצפה) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'קונים: פער בטיפול בהקונה (וריאנט 5)', 'השלם את החסר בהקונה (קונה פורטל לא נצפה) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהקונה (קונה פורטל לא נצפה) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהקונה. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־14,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והקונה חוזר למסלול טיפול פעיל.', 'קונים: קונה פורטל לא נצפה. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והקונה חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (קונים/קונה פורטל לא נצפה) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.buyer.buyer_package_expired', 'buyer', 'agent', 'follow_up_required', 'קונים: פער בטיפול בהקונה (וריאנט 6)', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'הקונה מציג פער (קונה חבילה פג תוקף) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'קונים: פער בטיפול בהקונה (וריאנט 6)', 'השלם את החסר בהקונה (קונה חבילה פג תוקף) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהקונה (קונה חבילה פג תוקף) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהקונה. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־14,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והקונה חוזר למסלול טיפול פעיל.', 'קונים: קונה חבילה פג תוקף. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והקונה חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (קונים/קונה חבילה פג תוקף) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.buyer.buyer_should_be_escalated', 'buyer', 'agent', 'manager_review', 'קונים: נדרש מבט ניהולי', 'נדרש מבט ניהולי או אישור לפני המשך.', 'נדרש מבט ניהולי או אישור לפני המשך.', 'הקונה הגיע לרף שמצדיק מעורבות ניהולית (קונה הוסלם). פעולות בעלות השפעה גבוהה דורשות אישור או ליווי כדי לאזן בין מהירות לבקרה. מומלץ להביא לבחינת מנהל לפני המשך.', 'קונים: נדרש מבט ניהולי', 'רכז את הנתונים הרלוונטיים להקונה והעבר לאישור/ליווי ניהולי לפני פעולה.', 'רכז את הנתונים הרלוונטיים להקונה והעבר לאישור/ליווי ניהולי לפני פעולה.', 'הקונה דורש החלטה ניהולית (קונה הוסלם). בחן את ההקשר, אשר או הנחה את הצעד הבא.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־14,000 ₪ בעסקה ממוצעת.', 'החלטה ניהולית בזמן מונעת טעויות יקרות בפעולות רגישות.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', 'קונים: קונה הוסלם. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', null, null, null, 'אוטומציה (קונים/קונה הוסלם) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.seller.seller_created', 'seller', 'agent', 'quick_win', 'מוכרים: המוכר חדש נכנס למערכת', 'המוכר נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'המוכר נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'המוכר נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון.', 'מוכרים: המוכר חדש נכנס למערכת', 'המוכר חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'המוכר חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט המוכר חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־16,000 ₪ בעסקה ממוצעת.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'המוכר מטופל, משויך ומקודם לצעד הבא במסלול.', 'מוכרים: מוכר נוצר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'המוכר מטופל, משויך ומקודם לצעד הבא במסלול.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא מוכר נוצר. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (מוכרים/מוכר נוצר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.seller.seller_twin_missing', 'seller', 'agent', 'follow_up_required', 'מוכרים: פער בטיפול בהמוכר', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'המוכר מציג פער (מוכר תאום חסר) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'מוכרים: פער בטיפול בהמוכר', 'השלם את החסר בהמוכר (מוכר תאום חסר) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהמוכר (מוכר תאום חסר) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהמוכר. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־16,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והמוכר חוזר למסלול טיפול פעיל.', 'מוכרים: מוכר תאום חסר. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והמוכר חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (מוכרים/מוכר תאום חסר) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
