  ('lib.seller.seller_should_be_asked_for_price_adjustment', 'seller', 'agent', 'manager_review', 'מוכרים: בחינת תמחור נדרשת (וריאנט 4)', 'נדרשת בחינת תמחור מבוססת עסקאות ושוק.', 'נדרשת בחינת תמחור מבוססת עסקאות ושוק.', 'זוהתה סוגיית תמחור במוכרים (מוכר התבקש מחיר התאמה). מחיר שאינו תואם עסקאות אזוריות פוגע בחשיפה ובסיכויי המכירה. מומלץ להציג ניתוח עסקאות משווה ולנהל שיחת תמחור עניינית מבוססת נתונים.', 'מוכרים: בחינת תמחור נדרשת (וריאנט 4)', 'הכן ניתוח עסקאות משווה להמוכר, והצג שיחת תמחור עניינית שמבוססת על נתוני שוק ולא על תחושה.', 'הכן ניתוח עסקאות משווה להמוכר, והצג שיחת תמחור עניינית שמבוססת על נתוני שוק ולא על תחושה.', 'קיים פער תמחור שמשפיע על חשיפה והמרה. ודא שיחה מבוססת נתונים מול הלקוח.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־16,000 ₪ בעסקה ממוצעת מסוג זה.', 'תמחור שגוי גורר ימי שיווק מתארכים וירידת ערך נתפסת.', 'התמחור מיושר לשוק והחשיפה משתפרת.', 'מוכרים: מוכר התבקש מחיר התאמה. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'התמחור מיושר לשוק והחשיפה משתפרת.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא מוכר התבקש מחיר התאמה. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (מוכרים/מוכר התבקש מחיר התאמה) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.seller.seller_should_approve_distribution', 'seller', 'agent', 'high_priority', 'מוכרים: מוכר אישור הפצה', 'זוהה אירוע במוכרים שמצדיק פעולה יזומה.', 'זוהה אירוע במוכרים שמצדיק פעולה יזומה.', 'זוהה אירוע במוכרים (מוכר אישור הפצה) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'מוכרים: מוכר אישור הפצה', 'בחן את ההקשר של מוכר אישור הפצה בהמוכר, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של מוכר אישור הפצה בהמוכר, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע במוכרים (מוכר אישור הפצה) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־16,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'מוכרים: מוכר אישור הפצה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (מוכרים/מוכר אישור הפצה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.seller.seller_has_acquisition_opportunity', 'seller', 'agent', 'revenue_opportunity', 'מוכרים: הזדמנות שכדאי לממש', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זוהתה הזדמנות במוכרים (מוכר בעל גיוס הזדמנות). הזדמנויות מסוג זה נסגרות מהר על ידי מי שפועל ראשון. מומלץ לבחון, לתעדף ולהתחיל בפעולה מבוקרת למימוש הערך.', 'מוכרים: הזדמנות שכדאי לממש', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'הזדמנות במוכרים ממתינה למימוש. ודא בעלות ברורה ולוח זמנים לפעולה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־16,000 ₪ בעסקה ממוצעת.', 'הזדמנויות לא ממומשות מתכלות במהירות וזולגות למתחרים.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', 'מוכרים: מוכר בעל גיוס הזדמנות. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', null, null, null, 'אוטומציה (מוכרים/מוכר בעל גיוס הזדמנות) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.seller.seller_should_be_converted_from_external_listing', 'seller', 'agent', 'growth_opportunity', 'מוכרים: התקדמות חיובית למינוף (וריאנט 2)', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'המוכר עבר אבן דרך חיובית (מוכר הומר מ חיצוני רישום). רגעי הצלחה הם הזדמנות למינוף: בקשת המלצה, הפניה או הרחבת קשר. מומלץ לתעד, לחזק את הקשר ולבחון צעד מנוף.', 'מוכרים: התקדמות חיובית למינוף (וריאנט 2)', 'נצל את ההצלחה בהמוכר: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'נצל את ההצלחה בהמוכר: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'המוכר רשם הצלחה. ודא תיעוד ומינוף (המלצה/הפניה/סיפור הצלחה) להגדלת ערך.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־16,000 ₪ בעסקה ממוצעת.', 'חלון המינוף לאחר הצלחה קצר — מומלץ לפעול בסמוך לאירוע.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', 'מוכרים: מוכר הומר מ חיצוני רישום. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא מוכר הומר מ חיצוני רישום. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', 'עדכון אישי בפורטל: הכנו עבורך מידע ממוקד בנושא מוכר הומר מ חיצוני רישום. הסוכן/ת שלך זמין/ה להמשך.', null, 'אוטומציה (מוכרים/מוכר הומר מ חיצוני רישום) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.seller.seller_belongs_to_hot_territory', 'seller', 'agent', 'high_priority', 'מוכרים: המוכר בכוונה גבוהה — חלון הזדמנות', 'המוכר מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'המוכר מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'המוכר מציג כעת סימני כוונה ובשלות גבוהים מהממוצע (מוכר שייך חם טריטוריה). זהו חלון הזדמנות קצר שבו פעולה מהירה ומקצועית עשויה להאיץ החלטה ולקדם הכנסה. מומלץ לתעדף ולפעול עוד היום.', 'מוכרים: המוכר בכוונה גבוהה — חלון הזדמנות', 'המוכר חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'המוכר חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'המוכר בעל פוטנציאל גבוה. ודא תיעדוף וטיפול מיידי; שקול ליווי או הקצאה לסוכן חזק.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־16,000 ₪ בעסקה ממוצעת.', 'חלון הכוונה הגבוהה קצר — עיכוב מקטין משמעותית את סיכויי הסגירה.', 'המוכר מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'מוכרים: מוכר שייך חם טריטוריה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'המוכר מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא מוכר שייך חם טריטוריה. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (מוכרים/מוכר שייך חם טריטוריה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.seller.seller_belongs_to_competitor_dominated_territory', 'seller', 'agent', 'growth_opportunity', 'מוכרים: המוכר מחובר להזדמנות נוספת (וריאנט 2)', 'המוכר מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'המוכר מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'המוכר מחובר להקשר נוסף במערכת (מוכר שייך בשליטת מתחרים טריטוריה). חיבורים חוצי-מודולים הם מקור יתרון: הם חושפים הזדמנות או מסלול פעולה שלא נראה במבט נקודתי. מומלץ לבחון את הקשר ולפעול למימוש הערך המשולב.', 'מוכרים: המוכר מחובר להזדמנות נוספת (וריאנט 2)', 'נצל את החיבור של המוכר (מוכר שייך בשליטת מתחרים טריטוריה) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'נצל את החיבור של המוכר (מוכר שייך בשליטת מתחרים טריטוריה) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'המוכר מחובר להזדמנות נוספת. ודא שהקשר מנוצל ולא נופל בין הכיסאות.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־16,000 ₪ בעסקה ממוצעת.', 'חיבורים חוצי-מודולים מתפוגגים אם לא פועלים עליהם בזמן.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', 'מוכרים: מוכר שייך בשליטת מתחרים טריטוריה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', null, null, null, 'אוטומציה (מוכרים/מוכר שייך בשליטת מתחרים טריטוריה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
