  ('lib.property.property_low_exposure', 'property', 'agent', 'high_priority', 'נכסים: נכס נמוך חשיפה', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים (נכס נמוך חשיפה) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'נכסים: נכס נמוך חשיפה', 'בחן את ההקשר של נכס נמוך חשיפה בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של נכס נמוך חשיפה בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בנכסים (נכס נמוך חשיפה) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'נכסים: נכס נמוך חשיפה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (נכסים/נכס נמוך חשיפה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_marketing_score_low', 'property', 'agent', 'high_priority', 'נכסים: שינוי ציון/ביצוע בהנכס', 'חל שינוי בציון/בביצועים של הנכס שמשנה תעדוף.', 'חל שינוי בציון/בביצועים של הנכס שמשנה תעדוף.', 'עודכן ציון או מדד ביצועים עבור הנכס (נכס שיווק ציון נמוך). שינוי בציון משקף שינוי אמיתי בסיכוי או בעדיפות, ולכן הוא נקודת החלטה: ייתכן שכדאי להאיץ, לעצור או להסיט מאמץ. מומלץ לבחון את הסיבה ולעדכן את התעדוף בהתאם.', 'נכסים: שינוי ציון/ביצוע בהנכס', 'בדוק מה הוביל לשינוי הציון בהנכס (נכס שיווק ציון נמוך), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'בדוק מה הוביל לשינוי הציון בהנכס (נכס שיווק ציון נמוך), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'ציון/ביצוע של הנכס השתנה. ודא שהתעדוף עודכן ושמשאבים מופנים למקום הנכון.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'שינוי ציון שלא מתורגם לפעולה מבזבז את יתרון המידע.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', 'נכסים: נכס שיווק ציון נמוך. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', null, null, null, 'אוטומציה (נכסים/נכס שיווק ציון נמוך) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_distribution_missing', 'property', 'agent', 'follow_up_required', 'נכסים: פער בטיפול בהנכס (וריאנט 9)', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'הנכס מציג פער (נכס הפצה חסר) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'נכסים: פער בטיפול בהנכס (וריאנט 9)', 'השלם את החסר בהנכס (נכס הפצה חסר) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהנכס (נכס הפצה חסר) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהנכס. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־15,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והנכס חוזר למסלול טיפול פעיל.', 'נכסים: נכס הפצה חסר. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והנכס חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (נכסים/נכס הפצה חסר) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.property.property_should_enter_daily_publishing', 'property', 'agent', 'high_priority', 'נכסים: נכס כניסה יומי פרסום', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים (נכס כניסה יומי פרסום) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'נכסים: נכס כניסה יומי פרסום', 'בחן את ההקשר של נכס כניסה יומי פרסום בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של נכס כניסה יומי פרסום בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בנכסים (נכס כניסה יומי פרסום) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'נכסים: נכס כניסה יומי פרסום. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (נכסים/נכס כניסה יומי פרסום) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.')
