values
  ('lib.property.property_should_get_recommendation_package', 'property', 'agent', 'quick_win', 'נכסים: הנכס בשל לקבלת ערך ממוקד', 'הגיע הזמן לספק להנכס ערך ממוקד ומותאם.', 'הגיע הזמן לספק להנכס ערך ממוקד ומותאם.', 'הנכס בשל לקבלת תוצר ערך מותאם (נכס קבלת המלצה חבילה). אספקת תובנה או חבילה רלוונטית בזמן הנכון מחזקת אמון ומקדמת החלטה. מומלץ להכין את התוצר ולהציגו באופן אישי.', 'נכסים: הנכס בשל לקבלת ערך ממוקד', 'הכן להנכס את התוצר המתאים (נכס קבלת המלצה חבילה) והצג אותו בפנייה אישית שמסבירה את הערך עבורו.', 'הכן להנכס את התוצר המתאים (נכס קבלת המלצה חבילה) והצג אותו בפנייה אישית שמסבירה את הערך עבורו.', 'הנכס ראוי לאספקת ערך ממוקד. ודא שהתוצר הוכן ונמסר באיכות גבוהה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'אספקת ערך בעיתוי הנכון מחזקת אמון ומקצרת את מסלול ההחלטה.', 'הנכס מקבל ערך מותאם שמקדם אותו לשלב הבא.', 'נכסים: נכס קבלת המלצה חבילה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הנכס מקבל ערך מותאם שמקדם אותו לשלב הבא.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא נכס קבלת המלצה חבילה. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', 'עדכון אישי בפורטל: הכנו עבורך מידע ממוקד בנושא נכס קבלת המלצה חבילה. הסוכן/ת שלך זמין/ה להמשך.', null, 'אוטומציה (נכסים/נכס קבלת המלצה חבילה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_has_matching_buyers', 'property', 'agent', 'revenue_opportunity', 'נכסים: הזדמנות שכדאי לממש', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זוהתה הזדמנות בנכסים (נכס בעל תואמים קונים). הזדמנויות מסוג זה נסגרות מהר על ידי מי שפועל ראשון. מומלץ לבחון, לתעדף ולהתחיל בפעולה מבוקרת למימוש הערך.', 'נכסים: הזדמנות שכדאי לממש', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'הזדמנות בנכסים ממתינה למימוש. ודא בעלות ברורה ולוח זמנים לפעולה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'הזדמנויות לא ממומשות מתכלות במהירות וזולגות למתחרים.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', 'נכסים: נכס בעל תואמים קונים. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', null, null, null, 'אוטומציה (נכסים/נכס בעל תואמים קונים) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_has_high_value_buyer', 'property', 'agent', 'high_priority', 'נכסים: נכס בעל ערך גבוה קונה', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים (נכס בעל ערך גבוה קונה) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'נכסים: נכס בעל ערך גבוה קונה', 'בחן את ההקשר של נכס בעל ערך גבוה קונה בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של נכס בעל ערך גבוה קונה בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בנכסים (נכס בעל ערך גבוה קונה) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'נכסים: נכס בעל ערך גבוה קונה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (נכסים/נכס בעל ערך גבוה קונה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_has_deal_created', 'property', 'agent', 'quick_win', 'נכסים: הנכס חדש נכנס למערכת (וריאנט 2)', 'הנכס נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הנכס נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הנכס נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון. (וריאנט 2)', 'נכסים: הנכס חדש נכנס למערכת (וריאנט 2)', 'הנכס חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'הנכס חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט הנכס חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'הנכס מטופל, משויך ומקודם לצעד הבא במסלול.', 'נכסים: נכס בעל עסקה נוצר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הנכס מטופל, משויך ומקודם לצעד הבא במסלול.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא נכס בעל עסקה נוצר. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (נכסים/נכס בעל עסקה נוצר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_deal_stalled', 'property', 'agent', 'deal_risk', 'נכסים: סיכון פעיל בהנכס', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'הנכס נמצא בסיכון (נכס עסקה נתקע). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'נכסים: סיכון פעיל בהנכס', 'טפל בשורש הסיכון בהנכס (נכס עסקה נתקע) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בהנכס (נכס עסקה נתקע) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'הנכס בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־15,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'נכסים: נכס עסקה נתקע. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (נכסים/נכס עסקה נתקע) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
