  ('lib.property.property_archived', 'property', 'agent', 'high_priority', 'נכסים: נכס אורכב', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים (נכס אורכב) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'נכסים: נכס אורכב', 'בחן את ההקשר של נכס אורכב בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של נכס אורכב בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בנכסים (נכס אורכב) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'נכסים: נכס אורכב. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (נכסים/נכס אורכב) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_exclusive_expiring', 'property', 'agent', 'follow_up_required', 'נכסים: פער בטיפול בהנכס (וריאנט 10)', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'הנכס מציג פער (נכס בלעדי פג) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'נכסים: פער בטיפול בהנכס (וריאנט 10)', 'השלם את החסר בהנכס (נכס בלעדי פג) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהנכס (נכס בלעדי פג) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהנכס. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־15,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והנכס חוזר למסלול טיפול פעיל.', 'נכסים: נכס בלעדי פג. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והנכס חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (נכסים/נכס בלעדי פג) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.property.property_duplicate_suspected', 'property', 'agent', 'manager_review', 'נכסים: בעיית איכות נתונים (וריאנט 2)', 'זוהתה בעיית איכות נתונים שמשבשת החלטות.', 'זוהתה בעיית איכות נתונים שמשבשת החלטות.', 'זוהתה בעיית איכות נתונים/מערכת (נכס כפילות חשד). נתונים שגויים פוגעים באמינות ההמלצות והדוחות. מומלץ לטפל בשורש הבעיה כדי לשמור על דיוק ההחלטות בכל המערכת.', 'נכסים: בעיית איכות נתונים (וריאנט 2)', 'טפל בבעיית הנתונים (נכס כפילות חשד) או הסלם לגורם המתאים כדי לשמור על דיוק.', 'טפל בבעיית הנתונים (נכס כפילות חשד) או הסלם לגורם המתאים כדי לשמור על דיוק.', 'קיימת בעיית איכות נתונים (נכס כפילות חשד). ודא טיפול כדי לשמר אמינות החלטות ודוחות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־15,000 ₪ בעסקה ממוצעת מסוג זה.', 'נתונים שגויים מתפשטים ופוגעים בכל שכבת ההחלטה.', 'איכות הנתונים משוחזרת והדיוק נשמר.', 'נכסים: נכס כפילות חשד. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'איכות הנתונים משוחזרת והדיוק נשמר.', null, null, null, 'אוטומציה (נכסים/נכס כפילות חשד) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.property.property_external_promoted', 'property', 'agent', 'high_priority', 'נכסים: נכס חיצוני קודם', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים (נכס חיצוני קודם) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'נכסים: נכס חיצוני קודם', 'בחן את ההקשר של נכס חיצוני קודם בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של נכס חיצוני קודם בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בנכסים (נכס חיצוני קודם) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'נכסים: נכס חיצוני קודם. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (נכסים/נכס חיצוני קודם) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_acquisition_opportunity', 'property', 'agent', 'revenue_opportunity', 'נכסים: הזדמנות שכדאי לממש (וריאנט 2)', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זוהתה הזדמנות בנכסים (נכס גיוס הזדמנות). הזדמנויות מסוג זה נסגרות מהר על ידי מי שפועל ראשון. מומלץ לבחון, לתעדף ולהתחיל בפעולה מבוקרת למימוש הערך.', 'נכסים: הזדמנות שכדאי לממש (וריאנט 2)', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'הזדמנות בנכסים ממתינה למימוש. ודא בעלות ברורה ולוח זמנים לפעולה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'הזדמנויות לא ממומשות מתכלות במהירות וזולגות למתחרים.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', 'נכסים: נכס גיוס הזדמנות. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', null, null, null, 'אוטומציה (נכסים/נכס גיוס הזדמנות) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_in_hot_street', 'property', 'agent', 'high_priority', 'נכסים: הנכס בכוונה גבוהה — חלון הזדמנות', 'הנכס מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'הנכס מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'הנכס מציג כעת סימני כוונה ובשלות גבוהים מהממוצע (נכס ב חם רחוב). זהו חלון הזדמנות קצר שבו פעולה מהירה ומקצועית עשויה להאיץ החלטה ולקדם הכנסה. מומלץ לתעדף ולפעול עוד היום.', 'נכסים: הנכס בכוונה גבוהה — חלון הזדמנות', 'הנכס חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הנכס חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הנכס בעל פוטנציאל גבוה. ודא תיעדוף וטיפול מיידי; שקול ליווי או הקצאה לסוכן חזק.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'חלון הכוונה הגבוהה קצר — עיכוב מקטין משמעותית את סיכויי הסגירה.', 'הנכס מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'נכסים: נכס ב חם רחוב. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הנכס מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא נכס ב חם רחוב. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (נכסים/נכס ב חם רחוב) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_in_weak_territory', 'property', 'agent', 'deal_risk', 'נכסים: סיכון פעיל בהנכס (וריאנט 2)', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'הנכס נמצא בסיכון (נכס ב חלש טריטוריה). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'נכסים: סיכון פעיל בהנכס (וריאנט 2)', 'טפל בשורש הסיכון בהנכס (נכס ב חלש טריטוריה) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בהנכס (נכס ב חלש טריטוריה) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'הנכס בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־15,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'נכסים: נכס ב חלש טריטוריה. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (נכסים/נכס ב חלש טריטוריה) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.property.property_in_competitor_threat_area', 'property', 'agent', 'high_priority', 'נכסים: נכס ב מתחרה איום אזור', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים (נכס ב מתחרה איום אזור) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'נכסים: נכס ב מתחרה איום אזור', 'בחן את ההקשר של נכס ב מתחרה איום אזור בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של נכס ב מתחרה איום אזור בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בנכסים (נכס ב מתחרה איום אזור) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'נכסים: נכס ב מתחרה איום אזור. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (נכסים/נכס ב מתחרה איום אזור) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_requires_manager_review', 'property', 'agent', 'manager_review', 'נכסים: נדרש מבט ניהולי', 'נדרש מבט ניהולי או אישור לפני המשך.', 'נדרש מבט ניהולי או אישור לפני המשך.', 'הנכס הגיע לרף שמצדיק מעורבות ניהולית (נכס דורש מנהל בדיקה). פעולות בעלות השפעה גבוהה דורשות אישור או ליווי כדי לאזן בין מהירות לבקרה. מומלץ להביא לבחינת מנהל לפני המשך.', 'נכסים: נדרש מבט ניהולי', 'רכז את הנתונים הרלוונטיים להנכס והעבר לאישור/ליווי ניהולי לפני פעולה.', 'רכז את הנתונים הרלוונטיים להנכס והעבר לאישור/ליווי ניהולי לפני פעולה.', 'הנכס דורש החלטה ניהולית (נכס דורש מנהל בדיקה). בחן את ההקשר, אשר או הנחה את הצעד הבא.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'החלטה ניהולית בזמן מונעת טעויות יקרות בפעולות רגישות.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', 'נכסים: נכס דורש מנהל בדיקה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', null, null, null, 'אוטומציה (נכסים/נכס דורש מנהל בדיקה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.')
