values
  ('lib.match.match_created', 'match', 'executive', 'quick_win', 'התאמות: ההתאמה חדש נכנס למערכת', 'ההתאמה נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'ההתאמה נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'מבט מנהלים: ההתאמה נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון.', 'התאמות: ההתאמה חדש נכנס למערכת', 'ההתאמה חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'ההתאמה חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט ההתאמה חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־22,000 ₪ בעסקה ממוצעת.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'ההתאמה מטופל, משויך ומקודם לצעד הבא במסלול.', 'התאמות: התאמה נוצר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההתאמה מטופל, משויך ומקודם לצעד הבא במסלול.', null, null, null, 'אוטומציה (התאמות/התאמה נוצר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.match.match_score_above_80', 'match', 'executive', 'high_priority', 'התאמות: ההתאמה בכוונה גבוהה — חלון הזדמנות', 'ההתאמה מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'ההתאמה מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'מבט מנהלים: ההתאמה מציג כעת סימני כוונה ובשלות גבוהים מהממוצע (התאמה ציון מעל 80). זהו חלון הזדמנות קצר שבו פעולה מהירה ומקצועית עשויה להאיץ החלטה ולקדם הכנסה. מומלץ לתעדף ולפעול עוד היום.', 'התאמות: ההתאמה בכוונה גבוהה — חלון הזדמנות', 'ההתאמה חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'ההתאמה חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'ההתאמה בעל פוטנציאל גבוה. ודא תיעדוף וטיפול מיידי; שקול ליווי או הקצאה לסוכן חזק.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־22,000 ₪ בעסקה ממוצעת.', 'חלון הכוונה הגבוהה קצר — עיכוב מקטין משמעותית את סיכויי הסגירה.', 'ההתאמה מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'התאמות: התאמה ציון מעל 80. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההתאמה מקודם להחלטה תוך מיצוי חלון ההזדמנות.', null, null, null, 'אוטומציה (התאמות/התאמה ציון מעל 80) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
