  ('lib.match.match_risk_high', 'match', 'executive', 'deal_risk', 'התאמות: סיכון פעיל בההתאמה', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'מבט מנהלים: ההתאמה נמצא בסיכון (התאמה סיכון גבוה). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'התאמות: סיכון פעיל בההתאמה', 'טפל בשורש הסיכון בההתאמה (התאמה סיכון גבוה) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בההתאמה (התאמה סיכון גבוה) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'ההתאמה בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־22,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'התאמות: התאמה סיכון גבוה. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (התאמות/התאמה סיכון גבוה) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.match.match_stale', 'match', 'executive', 'follow_up_required', 'התאמות: פער בטיפול בההתאמה', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'מבט מנהלים: ההתאמה מציג פער (התאמה מיושן) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'התאמות: פער בטיפול בההתאמה', 'השלם את החסר בההתאמה (התאמה מיושן) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בההתאמה (התאמה מיושן) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בההתאמה. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־22,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר וההתאמה חוזר למסלול טיפול פעיל.', 'התאמות: התאמה מיושן. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר וההתאמה חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (התאמות/התאמה מיושן) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.match.match_buyer_engaged', 'match', 'executive', 'high_priority', 'התאמות: התאמה קונה מעורב', 'זוהה אירוע בהתאמות שמצדיק פעולה יזומה.', 'זוהה אירוע בהתאמות שמצדיק פעולה יזומה.', 'מבט מנהלים: זוהה אירוע בהתאמות (התאמה קונה מעורב) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'התאמות: התאמה קונה מעורב', 'בחן את ההקשר של התאמה קונה מעורב בההתאמה, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של התאמה קונה מעורב בההתאמה, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בהתאמות (התאמה קונה מעורב) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־22,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'התאמות: התאמה קונה מעורב. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (התאמות/התאמה קונה מעורב) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.match.match_seller_risk_affecting_match', 'match', 'executive', 'deal_risk', 'התאמות: סיכון פעיל בההתאמה (וריאנט 2)', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'מבט מנהלים: ההתאמה נמצא בסיכון (התאמה מוכר סיכון משפיע התאמה). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'התאמות: סיכון פעיל בההתאמה (וריאנט 2)', 'טפל בשורש הסיכון בההתאמה (התאמה מוכר סיכון משפיע התאמה) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בההתאמה (התאמה מוכר סיכון משפיע התאמה) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'ההתאמה בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־22,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'התאמות: התאמה מוכר סיכון משפיע התאמה. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (התאמות/התאמה מוכר סיכון משפיע התאמה) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.match.match_needs_viewing', 'match', 'executive', 'follow_up_required', 'התאמות: ההתאמה דורש מעקב יזום', 'נדרש מעקב יזום כדי לשמר מומנטום מול ההתאמה.', 'נדרש מעקב יזום כדי לשמר מומנטום מול ההתאמה.', 'מבט מנהלים: ההתאמה דורש מעקב יזום (התאמה זקוק צפייה בנכס). היעדר המשכיות הוא הגורם המוביל לאובדן עסקאות. מומלץ לבצע מעקב מקצועי שממשיך את השיחה הקודמת ומקדם צעד מוחשי.', 'התאמות: ההתאמה דורש מעקב יזום', 'בצע מעקב לההתאמה שממשיך מהנקודה האחרונה, עם צעד המשך ברור ומועד הבא מתואם.', 'בצע מעקב לההתאמה שממשיך מהנקודה האחרונה, עם צעד המשך ברור ומועד הבא מתואם.', 'ההתאמה ממתין למעקב. ודא שהמעגל נסגר כדי לא לאבד התקדמות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־22,000 ₪ בעסקה ממוצעת מסוג זה.', 'כל יום ללא מעקב מקטין את סבירות ההמרה.', 'המעקב בוצע וההתאמה מקודם עם צעד המשך מתואם.', 'התאמות: התאמה זקוק צפייה בנכס. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'המעקב בוצע וההתאמה מקודם עם צעד המשך מתואם.', null, null, null, 'אוטומציה (התאמות/התאמה זקוק צפייה בנכס) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
