  ('lib.match.match_in_competitor_area', 'match', 'executive', 'high_priority', 'התאמות: התאמה ב מתחרה אזור', 'זוהה אירוע בהתאמות שמצדיק פעולה יזומה.', 'זוהה אירוע בהתאמות שמצדיק פעולה יזומה.', 'מבט מנהלים: זוהה אירוע בהתאמות (התאמה ב מתחרה אזור) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'התאמות: התאמה ב מתחרה אזור', 'בחן את ההקשר של התאמה ב מתחרה אזור בההתאמה, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של התאמה ב מתחרה אזור בההתאמה, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בהתאמות (התאמה ב מתחרה אזור) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־22,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'התאמות: התאמה ב מתחרה אזור. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (התאמות/התאמה ב מתחרה אזור) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.match.match_missing_communication', 'match', 'executive', 'follow_up_required', 'התאמות: פער בטיפול בההתאמה (וריאנט 2)', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'מבט מנהלים: ההתאמה מציג פער (התאמה חסר תקשורת) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'התאמות: פער בטיפול בההתאמה (וריאנט 2)', 'השלם את החסר בההתאמה (התאמה חסר תקשורת) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בההתאמה (התאמה חסר תקשורת) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בההתאמה. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־22,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר וההתאמה חוזר למסלול טיפול פעיל.', 'התאמות: התאמה חסר תקשורת. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר וההתאמה חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (התאמות/התאמה חסר תקשורת) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.match.match_has_broken_commitment', 'match', 'executive', 'customer_risk', 'התאמות: אירוע שדורש סגירה מסודרת (וריאנט 2)', 'זוהה אירוע שלילי שדורש סגירה מסודרת או הצלה.', 'זוהה אירוע שלילי שדורש סגירה מסודרת או הצלה.', 'מבט מנהלים: ההתאמה עבר אירוע שלילי (התאמה בעל הופרה התחייבות). חשוב לסגור מסודר, ללמוד את הסיבה, ולבחון אם יש מסלול הצלה. טיפול נכון גם באירוע שלילי שומר על מוניטין ועל פוטנציאל עתידי.', 'התאמות: אירוע שדורש סגירה מסודרת (וריאנט 2)', 'סגור מסודר את ההתאמה, תעד את הסיבה, ובחן אם קיים מסלול הצלה או חידוש קשר עתידי.', 'סגור מסודר את ההתאמה, תעד את הסיבה, ובחן אם קיים מסלול הצלה או חידוש קשר עתידי.', 'ההתאמה ברצף שלילי. ודא סגירה מסודרת ולמידה לשימור איכות התהליך.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־22,000 ₪ בעסקה ממוצעת מסוג זה.', 'סגירה לא מסודרת פוגעת בנתונים ובמוניטין.', 'האירוע נסגר מסודר, מתועד, ונבחנת אפשרות הצלה.', 'התאמות: התאמה בעל הופרה התחייבות. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'האירוע נסגר מסודר, מתועד, ונבחנת אפשרות הצלה.', null, null, null, 'אוטומציה (התאמות/התאמה בעל הופרה התחייבות) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.match.match_financing_risk', 'match', 'executive', 'deal_risk', 'התאמות: סיכון פעיל בההתאמה (וריאנט 4)', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'מבט מנהלים: ההתאמה נמצא בסיכון (התאמה מימון סיכון). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'התאמות: סיכון פעיל בההתאמה (וריאנט 4)', 'טפל בשורש הסיכון בההתאמה (התאמה מימון סיכון) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בההתאמה (התאמה מימון סיכון) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'ההתאמה בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־22,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'התאמות: התאמה מימון סיכון. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (התאמות/התאמה מימון סיכון) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.match.match_pricing_risk', 'match', 'executive', 'manager_review', 'התאמות: בחינת תמחור נדרשת', 'נדרשת בחינת תמחור מבוססת עסקאות ושוק.', 'נדרשת בחינת תמחור מבוססת עסקאות ושוק.', 'מבט מנהלים: זוהתה סוגיית תמחור בהתאמות (התאמה תמחור סיכון). מחיר שאינו תואם עסקאות אזוריות פוגע בחשיפה ובסיכויי המכירה. מומלץ להציג ניתוח עסקאות משווה ולנהל שיחת תמחור עניינית מבוססת נתונים.', 'התאמות: בחינת תמחור נדרשת', 'הכן ניתוח עסקאות משווה לההתאמה, והצג שיחת תמחור עניינית שמבוססת על נתוני שוק ולא על תחושה.', 'הכן ניתוח עסקאות משווה לההתאמה, והצג שיחת תמחור עניינית שמבוססת על נתוני שוק ולא על תחושה.', 'קיים פער תמחור שמשפיע על חשיפה והמרה. ודא שיחה מבוססת נתונים מול הלקוח.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־22,000 ₪ בעסקה ממוצעת מסוג זה.', 'תמחור שגוי גורר ימי שיווק מתארכים וירידת ערך נתפסת.', 'התמחור מיושר לשוק והחשיפה משתפרת.', 'התאמות: התאמה תמחור סיכון. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'התמחור מיושר לשוק והחשיפה משתפרת.', null, null, null, 'אוטומציה (התאמות/התאמה תמחור סיכון) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.match.match_needs_manager_review', 'match', 'executive', 'manager_review', 'התאמות: נדרש מבט ניהולי', 'נדרש מבט ניהולי או אישור לפני המשך.', 'נדרש מבט ניהולי או אישור לפני המשך.', 'מבט מנהלים: ההתאמה הגיע לרף שמצדיק מעורבות ניהולית (התאמה זקוק מנהל בדיקה). פעולות בעלות השפעה גבוהה דורשות אישור או ליווי כדי לאזן בין מהירות לבקרה. מומלץ להביא לבחינת מנהל לפני המשך.', 'התאמות: נדרש מבט ניהולי', 'רכז את הנתונים הרלוונטיים לההתאמה והעבר לאישור/ליווי ניהולי לפני פעולה.', 'רכז את הנתונים הרלוונטיים לההתאמה והעבר לאישור/ליווי ניהולי לפני פעולה.', 'ההתאמה דורש החלטה ניהולית (התאמה זקוק מנהל בדיקה). בחן את ההקשר, אשר או הנחה את הצעד הבא.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־22,000 ₪ בעסקה ממוצעת.', 'החלטה ניהולית בזמן מונעת טעויות יקרות בפעולות רגישות.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', 'התאמות: התאמה זקוק מנהל בדיקה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', null, null, null, 'אוטומציה (התאמות/התאמה זקוק מנהל בדיקה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.match.match_should_update_decision_brain', 'match', 'executive', 'follow_up_required', 'התאמות: ההתאמה זקוק לעדכון/קידום (וריאנט 5)', 'ההתאמה זקוק לעדכון/קידום כדי לשמור על רצף תקין.', 'ההתאמה זקוק לעדכון/קידום כדי לשמור על רצף תקין.', 'מבט מנהלים: ההתאמה הגיע לנקודה שמחייבת עדכון או קידום שלב (התאמה עדכון החלטה מוח). שמירה על סנכרון ורצף בין השלבים מונעת תקיעות ומבטיחה שהמידע שמניע החלטות נשאר עדכני. מומלץ לבצע את העדכון ולוודא המשכיות.', 'התאמות: ההתאמה זקוק לעדכון/קידום (וריאנט 5)', 'בצע את העדכון/הקידום הנדרש לההתאמה (התאמה עדכון החלטה מוח), וודא שהשלב הבא ברור ומתואם.', 'בצע את העדכון/הקידום הנדרש לההתאמה (התאמה עדכון החלטה מוח), וודא שהשלב הבא ברור ומתואם.', 'ההתאמה ממתין לעדכון/קידום. ודא שאין תקיעות ושכל המודולים מסונכרנים.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־22,000 ₪ בעסקה ממוצעת.', 'שלב שלא מתקדם תוקע את כל השרשרת שאחריו.', 'ההתאמה מעודכן, מסונכרן וממשיך ברצף תקין.', 'התאמות: התאמה עדכון החלטה מוח. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההתאמה מעודכן, מסונכרן וממשיך ברצף תקין.', null, null, null, 'אוטומציה (התאמות/התאמה עדכון החלטה מוח) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.match.match_from_social_lead', 'match', 'executive', 'growth_opportunity', 'התאמות: ההתאמה מחובר להזדמנות נוספת', 'ההתאמה מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'ההתאמה מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'מבט מנהלים: ההתאמה מחובר להקשר נוסף במערכת (התאמה מ חברתי ליד). חיבורים חוצי-מודולים הם מקור יתרון: הם חושפים הזדמנות או מסלול פעולה שלא נראה במבט נקודתי. מומלץ לבחון את הקשר ולפעול למימוש הערך המשולב.', 'התאמות: ההתאמה מחובר להזדמנות נוספת', 'נצל את החיבור של ההתאמה (התאמה מ חברתי ליד) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'נצל את החיבור של ההתאמה (התאמה מ חברתי ליד) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'ההתאמה מחובר להזדמנות נוספת. ודא שהקשר מנוצל ולא נופל בין הכיסאות.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־22,000 ₪ בעסקה ממוצעת.', 'חיבורים חוצי-מודולים מתפוגגים אם לא פועלים עליהם בזמן.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', 'התאמות: התאמה מ חברתי ליד. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', null, null, null, 'אוטומציה (התאמות/התאמה מ חברתי ליד) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
