  ('lib.match.match_confidence_low', 'match', 'executive', 'high_priority', 'התאמות: שינוי ציון/ביצוע בההתאמה (וריאנט 3)', 'חל שינוי בציון/בביצועים של ההתאמה שמשנה תעדוף.', 'חל שינוי בציון/בביצועים של ההתאמה שמשנה תעדוף.', 'מבט מנהלים: עודכן ציון או מדד ביצועים עבור ההתאמה (התאמה ביטחון נמוך). שינוי בציון משקף שינוי אמיתי בסיכוי או בעדיפות, ולכן הוא נקודת החלטה: ייתכן שכדאי להאיץ, לעצור או להסיט מאמץ. מומלץ לבחון את הסיבה ולעדכן את התעדוף בהתאם.', 'התאמות: שינוי ציון/ביצוע בההתאמה (וריאנט 3)', 'בדוק מה הוביל לשינוי הציון בההתאמה (התאמה ביטחון נמוך), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'בדוק מה הוביל לשינוי הציון בההתאמה (התאמה ביטחון נמוך), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'ציון/ביצוע של ההתאמה השתנה. ודא שהתעדוף עודכן ושמשאבים מופנים למקום הנכון.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־22,000 ₪ בעסקה ממוצעת.', 'שינוי ציון שלא מתורגם לפעולה מבזבז את יתרון המידע.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', 'התאמות: התאמה ביטחון נמוך. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', null, null, null, 'אוטומציה (התאמות/התאמה ביטחון נמוך) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.deal.deal_created', 'deal', 'executive', 'quick_win', 'עסקאות: העסקה חדש נכנס למערכת', 'העסקה נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'העסקה נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'מבט מנהלים: העסקה נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון.', 'עסקאות: העסקה חדש נכנס למערכת', 'העסקה חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'העסקה חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט העסקה חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־24,000 ₪ בעסקה ממוצעת.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'העסקה מטופל, משויך ומקודם לצעד הבא במסלול.', 'עסקאות: עסקה נוצר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'העסקה מטופל, משויך ומקודם לצעד הבא במסלול.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא עסקה נוצר. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (עסקאות/עסקה נוצר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.deal.deal_stage_changed', 'deal', 'executive', 'follow_up_required', 'עסקאות: העסקה זקוק לעדכון/קידום', 'העסקה זקוק לעדכון/קידום כדי לשמור על רצף תקין.', 'העסקה זקוק לעדכון/קידום כדי לשמור על רצף תקין.', 'מבט מנהלים: העסקה הגיע לנקודה שמחייבת עדכון או קידום שלב (עסקה שלב השתנה). שמירה על סנכרון ורצף בין השלבים מונעת תקיעות ומבטיחה שהמידע שמניע החלטות נשאר עדכני. מומלץ לבצע את העדכון ולוודא המשכיות.', 'עסקאות: העסקה זקוק לעדכון/קידום', 'בצע את העדכון/הקידום הנדרש להעסקה (עסקה שלב השתנה), וודא שהשלב הבא ברור ומתואם.', 'בצע את העדכון/הקידום הנדרש להעסקה (עסקה שלב השתנה), וודא שהשלב הבא ברור ומתואם.', 'העסקה ממתין לעדכון/קידום. ודא שאין תקיעות ושכל המודולים מסונכרנים.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־24,000 ₪ בעסקה ממוצעת.', 'שלב שלא מתקדם תוקע את כל השרשרת שאחריו.', 'העסקה מעודכן, מסונכרן וממשיך ברצף תקין.', 'עסקאות: עסקה שלב השתנה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'העסקה מעודכן, מסונכרן וממשיך ברצף תקין.', null, null, null, 'אוטומציה (עסקאות/עסקה שלב השתנה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.deal.deal_stuck_in_stage', 'deal', 'executive', 'deal_risk', 'עסקאות: סיכון פעיל בהעסקה', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'מבט מנהלים: העסקה נמצא בסיכון (עסקה תקוע ב שלב). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'עסקאות: סיכון פעיל בהעסקה', 'טפל בשורש הסיכון בהעסקה (עסקה תקוע ב שלב) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בהעסקה (עסקה תקוע ב שלב) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'העסקה בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־24,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'עסקאות: עסקה תקוע ב שלב. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (עסקאות/עסקה תקוע ב שלב) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.deal.deal_at_risk', 'deal', 'executive', 'deal_risk', 'עסקאות: סיכון פעיל בהעסקה (וריאנט 2)', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'מבט מנהלים: העסקה נמצא בסיכון (עסקה ב סיכון). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'עסקאות: סיכון פעיל בהעסקה (וריאנט 2)', 'טפל בשורש הסיכון בהעסקה (עסקה ב סיכון) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בהעסקה (עסקה ב סיכון) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'העסקה בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־24,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'עסקאות: עסקה ב סיכון. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (עסקאות/עסקה ב סיכון) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.deal.deal_ready_to_close', 'deal', 'executive', 'high_priority', 'עסקאות: העסקה בכוונה גבוהה — חלון הזדמנות', 'העסקה מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'העסקה מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'מבט מנהלים: העסקה מציג כעת סימני כוונה ובשלות גבוהים מהממוצע (עסקה מוכן קרוב לסגירה). זהו חלון הזדמנות קצר שבו פעולה מהירה ומקצועית עשויה להאיץ החלטה ולקדם הכנסה. מומלץ לתעדף ולפעול עוד היום.', 'עסקאות: העסקה בכוונה גבוהה — חלון הזדמנות', 'העסקה חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'העסקה חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'העסקה בעל פוטנציאל גבוה. ודא תיעדוף וטיפול מיידי; שקול ליווי או הקצאה לסוכן חזק.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־24,000 ₪ בעסקה ממוצעת.', 'חלון הכוונה הגבוהה קצר — עיכוב מקטין משמעותית את סיכויי הסגירה.', 'העסקה מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'עסקאות: עסקה מוכן קרוב לסגירה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'העסקה מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא עסקה מוכן קרוב לסגירה. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (עסקאות/עסקה מוכן קרוב לסגירה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.')
