  ('lib.deal.deal_seller_risk_high', 'deal', 'executive', 'deal_risk', 'עסקאות: סיכון פעיל בהעסקה (וריאנט 6)', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'מבט מנהלים: העסקה נמצא בסיכון (עסקה מוכר סיכון גבוה). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'עסקאות: סיכון פעיל בהעסקה (וריאנט 6)', 'טפל בשורש הסיכון בהעסקה (עסקה מוכר סיכון גבוה) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בהעסקה (עסקה מוכר סיכון גבוה) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'העסקה בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־24,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'עסקאות: עסקה מוכר סיכון גבוה. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (עסקאות/עסקה מוכר סיכון גבוה) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.deal.deal_property_price_risk', 'deal', 'executive', 'manager_review', 'עסקאות: בחינת תמחור נדרשת', 'נדרשת בחינת תמחור מבוססת עסקאות ושוק.', 'נדרשת בחינת תמחור מבוססת עסקאות ושוק.', 'מבט מנהלים: זוהתה סוגיית תמחור בעסקאות (עסקה נכס מחיר סיכון). מחיר שאינו תואם עסקאות אזוריות פוגע בחשיפה ובסיכויי המכירה. מומלץ להציג ניתוח עסקאות משווה ולנהל שיחת תמחור עניינית מבוססת נתונים.', 'עסקאות: בחינת תמחור נדרשת', 'הכן ניתוח עסקאות משווה להעסקה, והצג שיחת תמחור עניינית שמבוססת על נתוני שוק ולא על תחושה.', 'הכן ניתוח עסקאות משווה להעסקה, והצג שיחת תמחור עניינית שמבוססת על נתוני שוק ולא על תחושה.', 'קיים פער תמחור שמשפיע על חשיפה והמרה. ודא שיחה מבוססת נתונים מול הלקוח.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־24,000 ₪ בעסקה ממוצעת מסוג זה.', 'תמחור שגוי גורר ימי שיווק מתארכים וירידת ערך נתפסת.', 'התמחור מיושר לשוק והחשיפה משתפרת.', 'עסקאות: עסקה נכס מחיר סיכון. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'התמחור מיושר לשוק והחשיפה משתפרת.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא עסקה נכס מחיר סיכון. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (עסקאות/עסקה נכס מחיר סיכון) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.deal.deal_financing_risk', 'deal', 'executive', 'deal_risk', 'עסקאות: סיכון פעיל בהעסקה (וריאנט 7)', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'מבט מנהלים: העסקה נמצא בסיכון (עסקה מימון סיכון). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'עסקאות: סיכון פעיל בהעסקה (וריאנט 7)', 'טפל בשורש הסיכון בהעסקה (עסקה מימון סיכון) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בהעסקה (עסקה מימון סיכון) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'העסקה בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־24,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'עסקאות: עסקה מימון סיכון. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (עסקאות/עסקה מימון סיכון) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.deal.deal_lost_risk', 'deal', 'executive', 'customer_risk', 'עסקאות: אירוע שדורש סגירה מסודרת', 'זוהה אירוע שלילי שדורש סגירה מסודרת או הצלה.', 'זוהה אירוע שלילי שדורש סגירה מסודרת או הצלה.', 'מבט מנהלים: העסקה עבר אירוע שלילי (עסקה אבדה סיכון). חשוב לסגור מסודר, ללמוד את הסיבה, ולבחון אם יש מסלול הצלה. טיפול נכון גם באירוע שלילי שומר על מוניטין ועל פוטנציאל עתידי.', 'עסקאות: אירוע שדורש סגירה מסודרת', 'סגור מסודר את העסקה, תעד את הסיבה, ובחן אם קיים מסלול הצלה או חידוש קשר עתידי.', 'סגור מסודר את העסקה, תעד את הסיבה, ובחן אם קיים מסלול הצלה או חידוש קשר עתידי.', 'העסקה ברצף שלילי. ודא סגירה מסודרת ולמידה לשימור איכות התהליך.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־24,000 ₪ בעסקה ממוצעת מסוג זה.', 'סגירה לא מסודרת פוגעת בנתונים ובמוניטין.', 'האירוע נסגר מסודר, מתועד, ונבחנת אפשרות הצלה.', 'עסקאות: עסקה אבדה סיכון. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'האירוע נסגר מסודר, מתועד, ונבחנת אפשרות הצלה.', null, null, null, 'אוטומציה (עסקאות/עסקה אבדה סיכון) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.deal.deal_closed', 'deal', 'executive', 'growth_opportunity', 'עסקאות: התקדמות חיובית למינוף', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'מבט מנהלים: העסקה עבר אבן דרך חיובית (עסקה נסגרה). רגעי הצלחה הם הזדמנות למינוף: בקשת המלצה, הפניה או הרחבת קשר. מומלץ לתעד, לחזק את הקשר ולבחון צעד מנוף.', 'עסקאות: התקדמות חיובית למינוף', 'נצל את ההצלחה בהעסקה: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'נצל את ההצלחה בהעסקה: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'העסקה רשם הצלחה. ודא תיעוד ומינוף (המלצה/הפניה/סיפור הצלחה) להגדלת ערך.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־24,000 ₪ בעסקה ממוצעת.', 'חלון המינוף לאחר הצלחה קצר — מומלץ לפעול בסמוך לאירוע.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', 'עסקאות: עסקה נסגרה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא עסקה נסגרה. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', 'עדכון אישי בפורטל: הכנו עבורך מידע ממוקד בנושא עסקה נסגרה. הסוכן/ת שלך זמין/ה להמשך.', null, 'אוטומציה (עסקאות/עסקה נסגרה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.')
