  ('lib.deal.deal_should_create_closing_checklist', 'deal', 'executive', 'deal_risk', 'עסקאות: מסמך חסר חוסם התקדמות (וריאנט 3)', 'חסרים מסמכים שעלולים לחסום התקדמות.', 'חסרים מסמכים שעלולים לחסום התקדמות.', 'מבט מנהלים: זוהה חוסר במסמך/אישור הנדרש להמשך (עסקה יצירת סגירה רשימת בדיקה). מסמכים חסרים חוסמים פרסום, חתימה או התקדמות עסקה. מומלץ להשלים את רשימת המסמכים ולוודא שאין חסם פתוח.', 'עסקאות: מסמך חסר חוסם התקדמות (וריאנט 3)', 'השלם את רשימת המסמכים הנדרשת להעסקה (עסקה יצירת סגירה רשימת בדיקה) כדי לפתוח את החסם להמשך.', 'השלם את רשימת המסמכים הנדרשת להעסקה (עסקה יצירת סגירה רשימת בדיקה) כדי לפתוח את החסם להמשך.', 'קיים חסם מסמכים בהעסקה. ודא השלמה כדי שלא לעכב פרסום או עסקה.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־24,000 ₪ בעסקה ממוצעת מסוג זה.', 'מסמך חסר עלול לעצור עסקה ברגע הקריטי.', 'רשימת המסמכים מושלמת והחסם נפתח.', 'עסקאות: עסקה יצירת סגירה רשימת בדיקה. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'רשימת המסמכים מושלמת והחסם נפתח.', null, null, null, 'אוטומציה (עסקאות/עסקה יצירת סגירה רשימת בדיקה) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.deal.deal_requires_manager_intervention', 'deal', 'executive', 'manager_review', 'עסקאות: נדרש מבט ניהולי', 'נדרש מבט ניהולי או אישור לפני המשך.', 'נדרש מבט ניהולי או אישור לפני המשך.', 'מבט מנהלים: העסקה הגיע לרף שמצדיק מעורבות ניהולית (עסקה דורש מנהל התערבות). פעולות בעלות השפעה גבוהה דורשות אישור או ליווי כדי לאזן בין מהירות לבקרה. מומלץ להביא לבחינת מנהל לפני המשך.', 'עסקאות: נדרש מבט ניהולי', 'רכז את הנתונים הרלוונטיים להעסקה והעבר לאישור/ליווי ניהולי לפני פעולה.', 'רכז את הנתונים הרלוונטיים להעסקה והעבר לאישור/ליווי ניהולי לפני פעולה.', 'העסקה דורש החלטה ניהולית (עסקה דורש מנהל התערבות). בחן את ההקשר, אשר או הנחה את הצעד הבא.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־24,000 ₪ בעסקה ממוצעת.', 'החלטה ניהולית בזמן מונעת טעויות יקרות בפעולות רגישות.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', 'עסקאות: עסקה דורש מנהל התערבות. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', null, null, null, 'אוטומציה (עסקאות/עסקה דורש מנהל התערבות) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.deal.deal_requires_agent_follow_up', 'deal', 'executive', 'follow_up_required', 'עסקאות: העסקה דורש מעקב יזום', 'נדרש מעקב יזום כדי לשמר מומנטום מול העסקה.', 'נדרש מעקב יזום כדי לשמר מומנטום מול העסקה.', 'מבט מנהלים: העסקה דורש מעקב יזום (עסקה דורש סוכן מעקב). היעדר המשכיות הוא הגורם המוביל לאובדן עסקאות. מומלץ לבצע מעקב מקצועי שממשיך את השיחה הקודמת ומקדם צעד מוחשי.', 'עסקאות: העסקה דורש מעקב יזום', 'בצע מעקב להעסקה שממשיך מהנקודה האחרונה, עם צעד המשך ברור ומועד הבא מתואם.', 'בצע מעקב להעסקה שממשיך מהנקודה האחרונה, עם צעד המשך ברור ומועד הבא מתואם.', 'העסקה ממתין למעקב. ודא שהמעגל נסגר כדי לא לאבד התקדמות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־24,000 ₪ בעסקה ממוצעת מסוג זה.', 'כל יום ללא מעקב מקטין את סבירות ההמרה.', 'המעקב בוצע והעסקה מקודם עם צעד המשך מתואם.', 'עסקאות: עסקה דורש סוכן מעקב. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'המעקב בוצע והעסקה מקודם עם צעד המשך מתואם.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא עסקה דורש סוכן מעקב. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', 'עדכון אישי בפורטל: הכנו עבורך מידע ממוקד בנושא עסקה דורש סוכן מעקב. הסוכן/ת שלך זמין/ה להמשך.', null, 'אוטומציה (עסקאות/עסקה דורש סוכן מעקב) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.deal.deal_commitment_broken', 'deal', 'executive', 'customer_risk', 'עסקאות: אירוע שדורש סגירה מסודרת (וריאנט 3)', 'זוהה אירוע שלילי שדורש סגירה מסודרת או הצלה.', 'זוהה אירוע שלילי שדורש סגירה מסודרת או הצלה.', 'מבט מנהלים: העסקה עבר אירוע שלילי (עסקה התחייבות הופרה). חשוב לסגור מסודר, ללמוד את הסיבה, ולבחון אם יש מסלול הצלה. טיפול נכון גם באירוע שלילי שומר על מוניטין ועל פוטנציאל עתידי.', 'עסקאות: אירוע שדורש סגירה מסודרת (וריאנט 3)', 'סגור מסודר את העסקה, תעד את הסיבה, ובחן אם קיים מסלול הצלה או חידוש קשר עתידי.', 'סגור מסודר את העסקה, תעד את הסיבה, ובחן אם קיים מסלול הצלה או חידוש קשר עתידי.', 'העסקה ברצף שלילי. ודא סגירה מסודרת ולמידה לשימור איכות התהליך.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־24,000 ₪ בעסקה ממוצעת מסוג זה.', 'סגירה לא מסודרת פוגעת בנתונים ובמוניטין.', 'האירוע נסגר מסודר, מתועד, ונבחנת אפשרות הצלה.', 'עסקאות: עסקה התחייבות הופרה. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'האירוע נסגר מסודר, מתועד, ונבחנת אפשרות הצלה.', null, null, null, 'אוטומציה (עסקאות/עסקה התחייבות הופרה) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.deal.deal_commitment_fulfilled', 'deal', 'executive', 'growth_opportunity', 'עסקאות: התקדמות חיובית למינוף (וריאנט 2)', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'מבט מנהלים: העסקה עבר אבן דרך חיובית (עסקה התחייבות מומשה). רגעי הצלחה הם הזדמנות למינוף: בקשת המלצה, הפניה או הרחבת קשר. מומלץ לתעד, לחזק את הקשר ולבחון צעד מנוף.', 'עסקאות: התקדמות חיובית למינוף (וריאנט 2)', 'נצל את ההצלחה בהעסקה: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'נצל את ההצלחה בהעסקה: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'העסקה רשם הצלחה. ודא תיעוד ומינוף (המלצה/הפניה/סיפור הצלחה) להגדלת ערך.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־24,000 ₪ בעסקה ממוצעת.', 'חלון המינוף לאחר הצלחה קצר — מומלץ לפעול בסמוך לאירוע.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', 'עסקאות: עסקה התחייבות מומשה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא עסקה התחייבות מומשה. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', 'עדכון אישי בפורטל: הכנו עבורך מידע ממוקד בנושא עסקה התחייבות מומשה. הסוכן/ת שלך זמין/ה להמשך.', null, 'אוטומציה (עסקאות/עסקה התחייבות מומשה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
