  ('lib.territory.territory_recommendation_density_high', 'territory', 'acquisition', 'high_priority', 'טריטוריה: שינוי ציון/ביצוע בהטריטוריה', 'חל שינוי בציון/בביצועים של הטריטוריה שמשנה תעדוף.', 'חל שינוי בציון/בביצועים של הטריטוריה שמשנה תעדוף.', 'זווית גיוס: עודכן ציון או מדד ביצועים עבור הטריטוריה (טריטוריה המלצה צפיפות גבוה). שינוי בציון משקף שינוי אמיתי בסיכוי או בעדיפות, ולכן הוא נקודת החלטה: ייתכן שכדאי להאיץ, לעצור או להסיט מאמץ. מומלץ לבחון את הסיבה ולעדכן את התעדוף בהתאם.', 'טריטוריה: שינוי ציון/ביצוע בהטריטוריה', 'בדוק מה הוביל לשינוי הציון בהטריטוריה (טריטוריה המלצה צפיפות גבוה), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'בדוק מה הוביל לשינוי הציון בהטריטוריה (טריטוריה המלצה צפיפות גבוה), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'ציון/ביצוע של הטריטוריה השתנה. ודא שהתעדוף עודכן ושמשאבים מופנים למקום הנכון.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־18,000 ₪ בעסקה ממוצעת.', 'שינוי ציון שלא מתורגם לפעולה מבזבז את יתרון המידע.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', 'טריטוריה: טריטוריה המלצה צפיפות גבוה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', null, null, null, 'אוטומציה (טריטוריה/טריטוריה המלצה צפיפות גבוה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.territory.territory_coverage_gap', 'territory', 'acquisition', 'revenue_opportunity', 'טריטוריה: הזדמנות שכדאי לממש (וריאנט 7)', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זווית גיוס: זוהתה הזדמנות בטריטוריה (טריטוריה כיסוי פער). הזדמנויות מסוג זה נסגרות מהר על ידי מי שפועל ראשון. מומלץ לבחון, לתעדף ולהתחיל בפעולה מבוקרת למימוש הערך.', 'טריטוריה: הזדמנות שכדאי לממש (וריאנט 7)', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'הזדמנות בטריטוריה ממתינה למימוש. ודא בעלות ברורה ולוח זמנים לפעולה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־18,000 ₪ בעסקה ממוצעת.', 'הזדמנויות לא ממומשות מתכלות במהירות וזולגות למתחרים.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', 'טריטוריה: טריטוריה כיסוי פער. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', null, null, null, 'אוטומציה (טריטוריה/טריטוריה כיסוי פער) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.territory.territory_no_assigned_agent', 'territory', 'acquisition', 'manager_review', 'טריטוריה: בחינת ניתוב להטריטוריה', 'נדרשת בחינת ניתוב לסוכן המתאים ביותר.', 'נדרשת בחינת ניתוב לסוכן המתאים ביותר.', 'זווית גיוס: הטריטוריה מתאים לבחינת ניתוב (טריטוריה ללא שויך סוכן). שיוך נכון בין לקוח לסוכן בעל התמחות וזמינות מתאימים מעלה מהותית את סיכויי הסגירה. מומלץ לבחון את ההתאמה ולאשר שיוך מיטבי.', 'טריטוריה: בחינת ניתוב להטריטוריה', 'בחן את התאמת הטריטוריה לסוכן/אזור, והעבר לאישור ניתוב מיטבי.', 'בחן את התאמת הטריטוריה לסוכן/אזור, והעבר לאישור ניתוב מיטבי.', 'הטריטוריה מועמד לניתוב מחדש. ודא שיוך לסוכן החזק והמתאים ביותר לאזור/לצורך.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־18,000 ₪ בעסקה ממוצעת.', 'שיוך לא מיטבי שורף הזדמנות אצל הלקוח.', 'הטריטוריה משויך לסוכן המתאים ביותר ומקודם.', 'טריטוריה: טריטוריה ללא שויך סוכן. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הטריטוריה משויך לסוכן המתאים ביותר ומקודם.', null, null, null, 'אוטומציה (טריטוריה/טריטוריה ללא שויך סוכן) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.territory.territory_weak_agent_ownership', 'territory', 'acquisition', 'deal_risk', 'טריטוריה: סיכון פעיל בהטריטוריה (וריאנט 2)', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זווית גיוס: הטריטוריה נמצא בסיכון (טריטוריה חלש סוכן בעלות). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'טריטוריה: סיכון פעיל בהטריטוריה (וריאנט 2)', 'טפל בשורש הסיכון בהטריטוריה (טריטוריה חלש סוכן בעלות) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בהטריטוריה (טריטוריה חלש סוכן בעלות) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'הטריטוריה בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־18,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'טריטוריה: טריטוריה חלש סוכן בעלות. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (טריטוריה/טריטוריה חלש סוכן בעלות) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
