  ('lib.territory.territory_should_create_manager_review', 'territory', 'acquisition', 'manager_review', 'טריטוריה: נדרש מבט ניהולי', 'נדרש מבט ניהולי או אישור לפני המשך.', 'נדרש מבט ניהולי או אישור לפני המשך.', 'זווית גיוס: הטריטוריה הגיע לרף שמצדיק מעורבות ניהולית (טריטוריה יצירת מנהל בדיקה). פעולות בעלות השפעה גבוהה דורשות אישור או ליווי כדי לאזן בין מהירות לבקרה. מומלץ להביא לבחינת מנהל לפני המשך.', 'טריטוריה: נדרש מבט ניהולי', 'רכז את הנתונים הרלוונטיים להטריטוריה והעבר לאישור/ליווי ניהולי לפני פעולה.', 'רכז את הנתונים הרלוונטיים להטריטוריה והעבר לאישור/ליווי ניהולי לפני פעולה.', 'הטריטוריה דורש החלטה ניהולית (טריטוריה יצירת מנהל בדיקה). בחן את ההקשר, אשר או הנחה את הצעד הבא.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־18,000 ₪ בעסקה ממוצעת.', 'החלטה ניהולית בזמן מונעת טעויות יקרות בפעולות רגישות.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', 'טריטוריה: טריטוריה יצירת מנהל בדיקה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', null, null, null, 'אוטומציה (טריטוריה/טריטוריה יצירת מנהל בדיקה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.territory.territory_should_update_routing', 'territory', 'acquisition', 'follow_up_required', 'טריטוריה: הטריטוריה זקוק לעדכון/קידום', 'הטריטוריה זקוק לעדכון/קידום כדי לשמור על רצף תקין.', 'הטריטוריה זקוק לעדכון/קידום כדי לשמור על רצף תקין.', 'זווית גיוס: הטריטוריה הגיע לנקודה שמחייבת עדכון או קידום שלב (טריטוריה עדכון ניתוב). שמירה על סנכרון ורצף בין השלבים מונעת תקיעות ומבטיחה שהמידע שמניע החלטות נשאר עדכני. מומלץ לבצע את העדכון ולוודא המשכיות.', 'טריטוריה: הטריטוריה זקוק לעדכון/קידום', 'בצע את העדכון/הקידום הנדרש להטריטוריה (טריטוריה עדכון ניתוב), וודא שהשלב הבא ברור ומתואם.', 'בצע את העדכון/הקידום הנדרש להטריטוריה (טריטוריה עדכון ניתוב), וודא שהשלב הבא ברור ומתואם.', 'הטריטוריה ממתין לעדכון/קידום. ודא שאין תקיעות ושכל המודולים מסונכרנים.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־18,000 ₪ בעסקה ממוצעת.', 'שלב שלא מתקדם תוקע את כל השרשרת שאחריו.', 'הטריטוריה מעודכן, מסונכרן וממשיך ברצף תקין.', 'טריטוריה: טריטוריה עדכון ניתוב. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הטריטוריה מעודכן, מסונכרן וממשיך ברצף תקין.', null, null, null, 'אוטומציה (טריטוריה/טריטוריה עדכון ניתוב) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
