  ('lib.territory.hot_street_detected', 'territory', 'acquisition', 'high_priority', 'טריטוריה: הטריטוריה בכוונה גבוהה — חלון הזדמנות (וריאנט 3)', 'הטריטוריה מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'הטריטוריה מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'זווית גיוס: הטריטוריה מציג כעת סימני כוונה ובשלות גבוהים מהממוצע (חם רחוב זוהה). זהו חלון הזדמנות קצר שבו פעולה מהירה ומקצועית עשויה להאיץ החלטה ולקדם הכנסה. מומלץ לתעדף ולפעול עוד היום.', 'טריטוריה: הטריטוריה בכוונה גבוהה — חלון הזדמנות (וריאנט 3)', 'הטריטוריה חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הטריטוריה חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הטריטוריה בעל פוטנציאל גבוה. ודא תיעדוף וטיפול מיידי; שקול ליווי או הקצאה לסוכן חזק.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־18,000 ₪ בעסקה ממוצעת.', 'חלון הכוונה הגבוהה קצר — עיכוב מקטין משמעותית את סיכויי הסגירה.', 'הטריטוריה מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'טריטוריה: חם רחוב זוהה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הטריטוריה מקודם להחלטה תוך מיצוי חלון ההזדמנות.', null, null, null, 'אוטומציה (טריטוריה/חם רחוב זוהה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.territory.weak_street_detected', 'territory', 'acquisition', 'deal_risk', 'טריטוריה: סיכון פעיל בהטריטוריה (וריאנט 3)', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זווית גיוס: הטריטוריה נמצא בסיכון (חלש רחוב זוהה). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'טריטוריה: סיכון פעיל בהטריטוריה (וריאנט 3)', 'טפל בשורש הסיכון בהטריטוריה (חלש רחוב זוהה) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בהטריטוריה (חלש רחוב זוהה) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'הטריטוריה בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־18,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'טריטוריה: חלש רחוב זוהה. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (טריטוריה/חלש רחוב זוהה) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.territory.new_operating_area_added', 'territory', 'acquisition', 'quick_win', 'טריטוריה: הטריטוריה חדש נכנס למערכת', 'הטריטוריה נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הטריטוריה נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'זווית גיוס: הטריטוריה נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון.', 'טריטוריה: הטריטוריה חדש נכנס למערכת', 'הטריטוריה חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'הטריטוריה חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט הטריטוריה חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־18,000 ₪ בעסקה ממוצעת.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'הטריטוריה מטופל, משויך ומקודם לצעד הבא במסלול.', 'טריטוריה: חדש פעילות אזור נוסף. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הטריטוריה מטופל, משויך ומקודם לצעד הבא במסלול.', null, null, null, 'אוטומציה (טריטוריה/חדש פעילות אזור נוסף) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.territory.operating_area_disabled', 'territory', 'acquisition', 'high_priority', 'טריטוריה: פעילות אזור הושבת', 'זוהה אירוע בטריטוריה שמצדיק פעולה יזומה.', 'זוהה אירוע בטריטוריה שמצדיק פעולה יזומה.', 'זווית גיוס: זוהה אירוע בטריטוריה (פעילות אזור הושבת) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'טריטוריה: פעילות אזור הושבת', 'בחן את ההקשר של פעילות אזור הושבת בהטריטוריה, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של פעילות אזור הושבת בהטריטוריה, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בטריטוריה (פעילות אזור הושבת) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־18,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'טריטוריה: פעילות אזור הושבת. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (טריטוריה/פעילות אזור הושבת) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.territory.territory_data_confidence_low', 'territory', 'acquisition', 'high_priority', 'טריטוריה: שינוי ציון/ביצוע בהטריטוריה (וריאנט 2)', 'חל שינוי בציון/בביצועים של הטריטוריה שמשנה תעדוף.', 'חל שינוי בציון/בביצועים של הטריטוריה שמשנה תעדוף.', 'זווית גיוס: עודכן ציון או מדד ביצועים עבור הטריטוריה (טריטוריה נתונים ביטחון נמוך). שינוי בציון משקף שינוי אמיתי בסיכוי או בעדיפות, ולכן הוא נקודת החלטה: ייתכן שכדאי להאיץ, לעצור או להסיט מאמץ. מומלץ לבחון את הסיבה ולעדכן את התעדוף בהתאם.', 'טריטוריה: שינוי ציון/ביצוע בהטריטוריה (וריאנט 2)', 'בדוק מה הוביל לשינוי הציון בהטריטוריה (טריטוריה נתונים ביטחון נמוך), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'בדוק מה הוביל לשינוי הציון בהטריטוריה (טריטוריה נתונים ביטחון נמוך), והתאם את רמת המאמץ והצעד הבא בהתאם.', 'ציון/ביצוע של הטריטוריה השתנה. ודא שהתעדוף עודכן ושמשאבים מופנים למקום הנכון.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־18,000 ₪ בעסקה ממוצעת.', 'שינוי ציון שלא מתורגם לפעולה מבזבז את יתרון המידע.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', 'טריטוריה: טריטוריה נתונים ביטחון נמוך. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'התעדוף מעודכן ומשקף את הסיכוי האמיתי הנוכחי.', null, null, null, 'אוטומציה (טריטוריה/טריטוריה נתונים ביטחון נמוך) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.territory.territory_stale_recompute', 'territory', 'acquisition', 'follow_up_required', 'טריטוריה: פער בטיפול בהטריטוריה', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זווית גיוס: הטריטוריה מציג פער (טריטוריה מיושן חישוב מחדש) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'טריטוריה: פער בטיפול בהטריטוריה', 'השלם את החסר בהטריטוריה (טריטוריה מיושן חישוב מחדש) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהטריטוריה (טריטוריה מיושן חישוב מחדש) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהטריטוריה. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־18,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והטריטוריה חוזר למסלול טיפול פעיל.', 'טריטוריה: טריטוריה מיושן חישוב מחדש. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והטריטוריה חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (טריטוריה/טריטוריה מיושן חישוב מחדש) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.')
