  ('lib.transaction.transaction_data_conflict_detected', 'transaction', 'acquisition', 'manager_review', 'עסקאות ותמחור: בעיית איכות נתונים (וריאנט 3)', 'זוהתה בעיית איכות נתונים שמשבשת החלטות.', 'זוהתה בעיית איכות נתונים שמשבשת החלטות.', 'זווית גיוס: זוהתה בעיית איכות נתונים/מערכת (עסקה נתונים התנגשות זוהה). נתונים שגויים פוגעים באמינות ההמלצות והדוחות. מומלץ לטפל בשורש הבעיה כדי לשמור על דיוק ההחלטות בכל המערכת.', 'עסקאות ותמחור: בעיית איכות נתונים (וריאנט 3)', 'טפל בבעיית הנתונים (עסקה נתונים התנגשות זוהה) או הסלם לגורם המתאים כדי לשמור על דיוק.', 'טפל בבעיית הנתונים (עסקה נתונים התנגשות זוהה) או הסלם לגורם המתאים כדי לשמור על דיוק.', 'קיימת בעיית איכות נתונים (עסקה נתונים התנגשות זוהה). ודא טיפול כדי לשמר אמינות החלטות ודוחות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־12,000 ₪ בעסקה ממוצעת מסוג זה.', 'נתונים שגויים מתפשטים ופוגעים בכל שכבת ההחלטה.', 'איכות הנתונים משוחזרת והדיוק נשמר.', 'עסקאות ותמחור: עסקה נתונים התנגשות זוהה. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'איכות הנתונים משוחזרת והדיוק נשמר.', null, null, null, 'אוטומציה (עסקאות ותמחור/עסקה נתונים התנגשות זוהה) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.acquisition.acquisition_profile_created', 'acquisition', 'acquisition', 'quick_win', 'גיוס מלאי: ההזדמנות חדש נכנס למערכת', 'ההזדמנות נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'ההזדמנות נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'זווית גיוס: ההזדמנות נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון.', 'גיוס מלאי: ההזדמנות חדש נכנס למערכת', 'ההזדמנות חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'ההזדמנות חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט ההזדמנות חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־20,000 ₪ בעסקה ממוצעת.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'ההזדמנות מטופל, משויך ומקודם לצעד הבא במסלול.', 'גיוס מלאי: גיוס פרופיל נוצר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההזדמנות מטופל, משויך ומקודם לצעד הבא במסלול.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס פרופיל נוצר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.acquisition.high_score_acquisition', 'acquisition', 'acquisition', 'high_priority', 'גיוס מלאי: ההזדמנות בכוונה גבוהה — חלון הזדמנות', 'ההזדמנות מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'ההזדמנות מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'זווית גיוס: ההזדמנות מציג כעת סימני כוונה ובשלות גבוהים מהממוצע (גבוה ציון גיוס). זהו חלון הזדמנות קצר שבו פעולה מהירה ומקצועית עשויה להאיץ החלטה ולקדם הכנסה. מומלץ לתעדף ולפעול עוד היום.', 'גיוס מלאי: ההזדמנות בכוונה גבוהה — חלון הזדמנות', 'ההזדמנות חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'ההזדמנות חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'ההזדמנות בעל פוטנציאל גבוה. ודא תיעדוף וטיפול מיידי; שקול ליווי או הקצאה לסוכן חזק.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־20,000 ₪ בעסקה ממוצעת.', 'חלון הכוונה הגבוהה קצר — עיכוב מקטין משמעותית את סיכויי הסגירה.', 'ההזדמנות מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'גיוס מלאי: גבוה ציון גיוס. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההזדמנות מקודם להחלטה תוך מיצוי חלון ההזדמנות.', null, null, null, 'אוטומציה (גיוס מלאי/גבוה ציון גיוס) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
