  ('lib.acquisition.acquisition_task_created', 'acquisition', 'acquisition', 'quick_win', 'גיוס מלאי: ההזדמנות חדש נכנס למערכת (וריאנט 2)', 'ההזדמנות נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'ההזדמנות נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'זווית גיוס: ההזדמנות נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון. (וריאנט 2)', 'גיוס מלאי: ההזדמנות חדש נכנס למערכת (וריאנט 2)', 'ההזדמנות חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'ההזדמנות חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט ההזדמנות חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־20,000 ₪ בעסקה ממוצעת.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'ההזדמנות מטופל, משויך ומקודם לצעד הבא במסלול.', 'גיוס מלאי: גיוס משימה נוצר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההזדמנות מטופל, משויך ומקודם לצעד הבא במסלול.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס משימה נוצר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.acquisition.acquisition_contacted', 'acquisition', 'acquisition', 'high_priority', 'גיוס מלאי: גיוס יצירת קשר', 'זוהה אירוע בגיוס מלאי שמצדיק פעולה יזומה.', 'זוהה אירוע בגיוס מלאי שמצדיק פעולה יזומה.', 'זווית גיוס: זוהה אירוע בגיוס מלאי (גיוס יצירת קשר) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'גיוס מלאי: גיוס יצירת קשר', 'בחן את ההקשר של גיוס יצירת קשר בההזדמנות, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של גיוס יצירת קשר בההזדמנות, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בגיוס מלאי (גיוס יצירת קשר) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־20,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'גיוס מלאי: גיוס יצירת קשר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס יצירת קשר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.acquisition.acquisition_follow_up_due', 'acquisition', 'acquisition', 'follow_up_required', 'גיוס מלאי: ההזדמנות דורש מעקב יזום', 'נדרש מעקב יזום כדי לשמר מומנטום מול ההזדמנות.', 'נדרש מעקב יזום כדי לשמר מומנטום מול ההזדמנות.', 'זווית גיוס: ההזדמנות דורש מעקב יזום (גיוס מעקב להגשה). היעדר המשכיות הוא הגורם המוביל לאובדן עסקאות. מומלץ לבצע מעקב מקצועי שממשיך את השיחה הקודמת ומקדם צעד מוחשי.', 'גיוס מלאי: ההזדמנות דורש מעקב יזום', 'בצע מעקב לההזדמנות שממשיך מהנקודה האחרונה, עם צעד המשך ברור ומועד הבא מתואם.', 'בצע מעקב לההזדמנות שממשיך מהנקודה האחרונה, עם צעד המשך ברור ומועד הבא מתואם.', 'ההזדמנות ממתין למעקב. ודא שהמעגל נסגר כדי לא לאבד התקדמות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־20,000 ₪ בעסקה ממוצעת מסוג זה.', 'כל יום ללא מעקב מקטין את סבירות ההמרה.', 'המעקב בוצע וההזדמנות מקודם עם צעד המשך מתואם.', 'גיוס מלאי: גיוס מעקב להגשה. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'המעקב בוצע וההזדמנות מקודם עם צעד המשך מתואם.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס מעקב להגשה) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.acquisition.acquisition_follow_up_missed', 'acquisition', 'acquisition', 'deal_risk', 'גיוס מלאי: סיכון פעיל בההזדמנות', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זווית גיוס: ההזדמנות נמצא בסיכון (גיוס מעקב הוחמץ). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'גיוס מלאי: סיכון פעיל בההזדמנות', 'טפל בשורש הסיכון בההזדמנות (גיוס מעקב הוחמץ) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בההזדמנות (גיוס מעקב הוחמץ) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'ההזדמנות בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־20,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'גיוס מלאי: גיוס מעקב הוחמץ. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס מעקב הוחמץ) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.acquisition.acquisition_promoted_to_crm', 'acquisition', 'acquisition', 'growth_opportunity', 'גיוס מלאי: התקדמות חיובית למינוף', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'הושגה התקדמות חיובית — הזדמנות למנף את ההצלחה.', 'זווית גיוס: ההזדמנות עבר אבן דרך חיובית (גיוס קודם מערכת ניהול). רגעי הצלחה הם הזדמנות למינוף: בקשת המלצה, הפניה או הרחבת קשר. מומלץ לתעד, לחזק את הקשר ולבחון צעד מנוף.', 'גיוס מלאי: התקדמות חיובית למינוף', 'נצל את ההצלחה בההזדמנות: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'נצל את ההצלחה בההזדמנות: חזק את הקשר, ובחן בקשת המלצה/הפניה או הרחבת שירות.', 'ההזדמנות רשם הצלחה. ודא תיעוד ומינוף (המלצה/הפניה/סיפור הצלחה) להגדלת ערך.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־20,000 ₪ בעסקה ממוצעת.', 'חלון המינוף לאחר הצלחה קצר — מומלץ לפעול בסמוך לאירוע.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', 'גיוס מלאי: גיוס קודם מערכת ניהול. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההצלחה ממונפת לקשר מתמשך ולהזדמנות נוספת.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס קודם מערכת ניהול) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.acquisition.acquisition_marked_not_relevant', 'acquisition', 'acquisition', 'customer_risk', 'גיוס מלאי: אירוע שדורש סגירה מסודרת', 'זוהה אירוע שלילי שדורש סגירה מסודרת או הצלה.', 'זוהה אירוע שלילי שדורש סגירה מסודרת או הצלה.', 'זווית גיוס: ההזדמנות עבר אירוע שלילי (גיוס סומן לא רלוונטי). חשוב לסגור מסודר, ללמוד את הסיבה, ולבחון אם יש מסלול הצלה. טיפול נכון גם באירוע שלילי שומר על מוניטין ועל פוטנציאל עתידי.', 'גיוס מלאי: אירוע שדורש סגירה מסודרת', 'סגור מסודר את ההזדמנות, תעד את הסיבה, ובחן אם קיים מסלול הצלה או חידוש קשר עתידי.', 'סגור מסודר את ההזדמנות, תעד את הסיבה, ובחן אם קיים מסלול הצלה או חידוש קשר עתידי.', 'ההזדמנות ברצף שלילי. ודא סגירה מסודרת ולמידה לשימור איכות התהליך.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־20,000 ₪ בעסקה ממוצעת מסוג זה.', 'סגירה לא מסודרת פוגעת בנתונים ובמוניטין.', 'האירוע נסגר מסודר, מתועד, ונבחנת אפשרות הצלה.', 'גיוס מלאי: גיוס סומן לא רלוונטי. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'האירוע נסגר מסודר, מתועד, ונבחנת אפשרות הצלה.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס סומן לא רלוונטי) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.acquisition.acquisition_stale', 'acquisition', 'acquisition', 'follow_up_required', 'גיוס מלאי: פער בטיפול בההזדמנות', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זווית גיוס: ההזדמנות מציג פער (גיוס מיושן) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'גיוס מלאי: פער בטיפול בההזדמנות', 'השלם את החסר בההזדמנות (גיוס מיושן) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בההזדמנות (גיוס מיושן) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בההזדמנות. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־20,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר וההזדמנות חוזר למסלול טיפול פעיל.', 'גיוס מלאי: גיוס מיושן. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר וההזדמנות חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס מיושן) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.acquisition.acquisition_price_changed', 'acquisition', 'acquisition', 'manager_review', 'גיוס מלאי: בחינת תמחור נדרשת', 'נדרשת בחינת תמחור מבוססת עסקאות ושוק.', 'נדרשת בחינת תמחור מבוססת עסקאות ושוק.', 'זווית גיוס: זוהתה סוגיית תמחור בגיוס מלאי (גיוס מחיר השתנה). מחיר שאינו תואם עסקאות אזוריות פוגע בחשיפה ובסיכויי המכירה. מומלץ להציג ניתוח עסקאות משווה ולנהל שיחת תמחור עניינית מבוססת נתונים.', 'גיוס מלאי: בחינת תמחור נדרשת', 'הכן ניתוח עסקאות משווה לההזדמנות, והצג שיחת תמחור עניינית שמבוססת על נתוני שוק ולא על תחושה.', 'הכן ניתוח עסקאות משווה לההזדמנות, והצג שיחת תמחור עניינית שמבוססת על נתוני שוק ולא על תחושה.', 'קיים פער תמחור שמשפיע על חשיפה והמרה. ודא שיחה מבוססת נתונים מול הלקוח.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־20,000 ₪ בעסקה ממוצעת מסוג זה.', 'תמחור שגוי גורר ימי שיווק מתארכים וירידת ערך נתפסת.', 'התמחור מיושר לשוק והחשיפה משתפרת.', 'גיוס מלאי: גיוס מחיר השתנה. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'התמחור מיושר לשוק והחשיפה משתפרת.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס מחיר השתנה) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.acquisition.acquisition_duplicate_suspected', 'acquisition', 'acquisition', 'manager_review', 'גיוס מלאי: בעיית איכות נתונים', 'זוהתה בעיית איכות נתונים שמשבשת החלטות.', 'זוהתה בעיית איכות נתונים שמשבשת החלטות.', 'זווית גיוס: זוהתה בעיית איכות נתונים/מערכת (גיוס כפילות חשד). נתונים שגויים פוגעים באמינות ההמלצות והדוחות. מומלץ לטפל בשורש הבעיה כדי לשמור על דיוק ההחלטות בכל המערכת.', 'גיוס מלאי: בעיית איכות נתונים', 'טפל בבעיית הנתונים (גיוס כפילות חשד) או הסלם לגורם המתאים כדי לשמור על דיוק.', 'טפל בבעיית הנתונים (גיוס כפילות חשד) או הסלם לגורם המתאים כדי לשמור על דיוק.', 'קיימת בעיית איכות נתונים (גיוס כפילות חשד). ודא טיפול כדי לשמר אמינות החלטות ודוחות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־20,000 ₪ בעסקה ממוצעת מסוג זה.', 'נתונים שגויים מתפשטים ופוגעים בכל שכבת ההחלטה.', 'איכות הנתונים משוחזרת והדיוק נשמר.', 'גיוס מלאי: גיוס כפילות חשד. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'איכות הנתונים משוחזרת והדיוק נשמר.', null, null, null, 'אוטומציה (גיוס מלאי/גיוס כפילות חשד) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
