  ('lib.social.social_lead_should_notify_manager', 'social', 'agent', 'manager_review', 'לידים חברתיים: נדרש מבט ניהולי', 'נדרש מבט ניהולי או אישור לפני המשך.', 'נדרש מבט ניהולי או אישור לפני המשך.', 'הפנייה הגיע לרף שמצדיק מעורבות ניהולית (חברתי ליד התראה מנהל). פעולות בעלות השפעה גבוהה דורשות אישור או ליווי כדי לאזן בין מהירות לבקרה. מומלץ להביא לבחינת מנהל לפני המשך.', 'לידים חברתיים: נדרש מבט ניהולי', 'רכז את הנתונים הרלוונטיים להפנייה והעבר לאישור/ליווי ניהולי לפני פעולה.', 'רכז את הנתונים הרלוונטיים להפנייה והעבר לאישור/ליווי ניהולי לפני פעולה.', 'הפנייה דורש החלטה ניהולית (חברתי ליד התראה מנהל). בחן את ההקשר, אשר או הנחה את הצעד הבא.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־9,000 ₪ בעסקה ממוצעת.', 'החלטה ניהולית בזמן מונעת טעויות יקרות בפעולות רגישות.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', 'לידים חברתיים: חברתי ליד התראה מנהל. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', null, null, null, 'אוטומציה (לידים חברתיים/חברתי ליד התראה מנהל) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.portal.portal_created', 'portal', 'agent', 'quick_win', 'פורטל לקוחות: הלקוח חדש נכנס למערכת', 'הלקוח נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הלקוח נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הלקוח נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון.', 'פורטל לקוחות: הלקוח חדש נכנס למערכת', 'הלקוח חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'הלקוח חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט הלקוח חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־11,000 ₪ בעסקה ממוצעת.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'הלקוח מטופל, משויך ומקודם לצעד הבא במסלול.', 'פורטל לקוחות: פורטל נוצר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הלקוח מטופל, משויך ומקודם לצעד הבא במסלול.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא פורטל נוצר. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (פורטל לקוחות/פורטל נוצר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.portal.portal_ready', 'portal', 'agent', 'high_priority', 'פורטל לקוחות: הלקוח בכוונה גבוהה — חלון הזדמנות', 'הלקוח מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'הלקוח מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'הלקוח מציג כעת סימני כוונה ובשלות גבוהים מהממוצע (פורטל מוכן). זהו חלון הזדמנות קצר שבו פעולה מהירה ומקצועית עשויה להאיץ החלטה ולקדם הכנסה. מומלץ לתעדף ולפעול עוד היום.', 'פורטל לקוחות: הלקוח בכוונה גבוהה — חלון הזדמנות', 'הלקוח חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הלקוח חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הלקוח בעל פוטנציאל גבוה. ודא תיעדוף וטיפול מיידי; שקול ליווי או הקצאה לסוכן חזק.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־11,000 ₪ בעסקה ממוצעת.', 'חלון הכוונה הגבוהה קצר — עיכוב מקטין משמעותית את סיכויי הסגירה.', 'הלקוח מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'פורטל לקוחות: פורטל מוכן. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הלקוח מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא פורטל מוכן. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (פורטל לקוחות/פורטל מוכן) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.portal.portal_approved', 'portal', 'agent', 'high_priority', 'פורטל לקוחות: פורטל אושר', 'זוהה אירוע בפורטל לקוחות שמצדיק פעולה יזומה.', 'זוהה אירוע בפורטל לקוחות שמצדיק פעולה יזומה.', 'זוהה אירוע בפורטל לקוחות (פורטל אושר) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'פורטל לקוחות: פורטל אושר', 'בחן את ההקשר של פורטל אושר בהלקוח, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של פורטל אושר בהלקוח, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בפורטל לקוחות (פורטל אושר) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־11,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'פורטל לקוחות: פורטל אושר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (פורטל לקוחות/פורטל אושר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.portal.portal_link_copied', 'portal', 'agent', 'high_priority', 'פורטל לקוחות: פורטל קישור הועתק', 'זוהה אירוע בפורטל לקוחות שמצדיק פעולה יזומה.', 'זוהה אירוע בפורטל לקוחות שמצדיק פעולה יזומה.', 'זוהה אירוע בפורטל לקוחות (פורטל קישור הועתק) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'פורטל לקוחות: פורטל קישור הועתק', 'בחן את ההקשר של פורטל קישור הועתק בהלקוח, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של פורטל קישור הועתק בהלקוח, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בפורטל לקוחות (פורטל קישור הועתק) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־11,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'פורטל לקוחות: פורטל קישור הועתק. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (פורטל לקוחות/פורטל קישור הועתק) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
