  ('lib.website.property_inquiry_from_website', 'website', 'agent', 'growth_opportunity', 'לידים מאתרים: הפנייה מחובר להזדמנות נוספת', 'הפנייה מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'הפנייה מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'הפנייה מחובר להקשר נוסף במערכת (נכס פנייה מ אתר). חיבורים חוצי-מודולים הם מקור יתרון: הם חושפים הזדמנות או מסלול פעולה שלא נראה במבט נקודתי. מומלץ לבחון את הקשר ולפעול למימוש הערך המשולב.', 'לידים מאתרים: הפנייה מחובר להזדמנות נוספת', 'נצל את החיבור של הפנייה (נכס פנייה מ אתר) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'נצל את החיבור של הפנייה (נכס פנייה מ אתר) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'הפנייה מחובר להזדמנות נוספת. ודא שהקשר מנוצל ולא נופל בין הכיסאות.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־9,000 ₪ בעסקה ממוצעת.', 'חיבורים חוצי-מודולים מתפוגגים אם לא פועלים עליהם בזמן.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', 'לידים מאתרים: נכס פנייה מ אתר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', null, null, null, 'אוטומציה (לידים מאתרים/נכס פנייה מ אתר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.website.project_inquiry_from_website', 'website', 'agent', 'growth_opportunity', 'לידים מאתרים: הפנייה מחובר להזדמנות נוספת (וריאנט 2)', 'הפנייה מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'הפנייה מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'הפנייה מחובר להקשר נוסף במערכת (פרויקט פנייה מ אתר). חיבורים חוצי-מודולים הם מקור יתרון: הם חושפים הזדמנות או מסלול פעולה שלא נראה במבט נקודתי. מומלץ לבחון את הקשר ולפעול למימוש הערך המשולב.', 'לידים מאתרים: הפנייה מחובר להזדמנות נוספת (וריאנט 2)', 'נצל את החיבור של הפנייה (פרויקט פנייה מ אתר) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'נצל את החיבור של הפנייה (פרויקט פנייה מ אתר) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'הפנייה מחובר להזדמנות נוספת. ודא שהקשר מנוצל ולא נופל בין הכיסאות.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־9,000 ₪ בעסקה ממוצעת.', 'חיבורים חוצי-מודולים מתפוגגים אם לא פועלים עליהם בזמן.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', 'לידים מאתרים: פרויקט פנייה מ אתר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', null, null, null, 'אוטומציה (לידים מאתרים/פרויקט פנייה מ אתר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.website.valuation_request_from_website', 'website', 'agent', 'manager_review', 'לידים מאתרים: בחינת תמחור נדרשת', 'נדרשת בחינת תמחור מבוססת עסקאות ושוק.', 'נדרשת בחינת תמחור מבוססת עסקאות ושוק.', 'זוהתה סוגיית תמחור בלידים מאתרים (הערכת שווי בקשה מ אתר). מחיר שאינו תואם עסקאות אזוריות פוגע בחשיפה ובסיכויי המכירה. מומלץ להציג ניתוח עסקאות משווה ולנהל שיחת תמחור עניינית מבוססת נתונים.', 'לידים מאתרים: בחינת תמחור נדרשת', 'הכן ניתוח עסקאות משווה להפנייה, והצג שיחת תמחור עניינית שמבוססת על נתוני שוק ולא על תחושה.', 'הכן ניתוח עסקאות משווה להפנייה, והצג שיחת תמחור עניינית שמבוססת על נתוני שוק ולא על תחושה.', 'קיים פער תמחור שמשפיע על חשיפה והמרה. ודא שיחה מבוססת נתונים מול הלקוח.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־9,000 ₪ בעסקה ממוצעת מסוג זה.', 'תמחור שגוי גורר ימי שיווק מתארכים וירידת ערך נתפסת.', 'התמחור מיושר לשוק והחשיפה משתפרת.', 'לידים מאתרים: הערכת שווי בקשה מ אתר. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'התמחור מיושר לשוק והחשיפה משתפרת.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא הערכת שווי בקשה מ אתר. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (לידים מאתרים/הערכת שווי בקשה מ אתר) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
