  ('lib.website.recruitment_lead_from_website', 'website', 'agent', 'growth_opportunity', 'לידים מאתרים: הפנייה מחובר להזדמנות נוספת (וריאנט 5)', 'הפנייה מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'הפנייה מחובר להזדמנות/הקשר נוסף שכדאי לנצל.', 'הפנייה מחובר להקשר נוסף במערכת (גיוס ליד מ אתר). חיבורים חוצי-מודולים הם מקור יתרון: הם חושפים הזדמנות או מסלול פעולה שלא נראה במבט נקודתי. מומלץ לבחון את הקשר ולפעול למימוש הערך המשולב.', 'לידים מאתרים: הפנייה מחובר להזדמנות נוספת (וריאנט 5)', 'נצל את החיבור של הפנייה (גיוס ליד מ אתר) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'נצל את החיבור של הפנייה (גיוס ליד מ אתר) — פנה עם הקשר רלוונטי שמחבר בין הצרכים לצעד מקדם.', 'הפנייה מחובר להזדמנות נוספת. ודא שהקשר מנוצל ולא נופל בין הכיסאות.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־9,000 ₪ בעסקה ממוצעת.', 'חיבורים חוצי-מודולים מתפוגגים אם לא פועלים עליהם בזמן.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', 'לידים מאתרים: גיוס ליד מ אתר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הקשר מנוצל ומומר לערך עסקי מוחשי.', null, null, null, 'אוטומציה (לידים מאתרים/גיוס ליד מ אתר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.website.website_lead_high_intent', 'website', 'agent', 'high_priority', 'לידים מאתרים: הפנייה בכוונה גבוהה — חלון הזדמנות', 'הפנייה מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'הפנייה מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'הפנייה מציג כעת סימני כוונה ובשלות גבוהים מהממוצע (אתר ליד גבוה כוונה). זהו חלון הזדמנות קצר שבו פעולה מהירה ומקצועית עשויה להאיץ החלטה ולקדם הכנסה. מומלץ לתעדף ולפעול עוד היום.', 'לידים מאתרים: הפנייה בכוונה גבוהה — חלון הזדמנות', 'הפנייה חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הפנייה חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הפנייה בעל פוטנציאל גבוה. ודא תיעדוף וטיפול מיידי; שקול ליווי או הקצאה לסוכן חזק.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־9,000 ₪ בעסקה ממוצעת.', 'חלון הכוונה הגבוהה קצר — עיכוב מקטין משמעותית את סיכויי הסגירה.', 'הפנייה מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'לידים מאתרים: אתר ליד גבוה כוונה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הפנייה מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא אתר ליד גבוה כוונה. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, 'תודה על פנייתך. סוכן/ת מטעמנו ייצור/תיצור קשר בהקדם להמשך אישי בנושא אתר ליד גבוה כוונה.', 'אוטומציה (לידים מאתרים/אתר ליד גבוה כוונה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.website.website_lead_missing_phone', 'website', 'agent', 'follow_up_required', 'לידים מאתרים: פער בטיפול בהפנייה', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'הפנייה מציג פער (אתר ליד חסר טלפון) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'לידים מאתרים: פער בטיפול בהפנייה', 'השלם את החסר בהפנייה (אתר ליד חסר טלפון) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהפנייה (אתר ליד חסר טלפון) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהפנייה. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־9,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והפנייה חוזר למסלול טיפול פעיל.', 'לידים מאתרים: אתר ליד חסר טלפון. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והפנייה חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (לידים מאתרים/אתר ליד חסר טלפון) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.website.website_lead_should_route', 'website', 'agent', 'manager_review', 'לידים מאתרים: בחינת ניתוב להפנייה', 'נדרשת בחינת ניתוב לסוכן המתאים ביותר.', 'נדרשת בחינת ניתוב לסוכן המתאים ביותר.', 'הפנייה מתאים לבחינת ניתוב (אתר ליד ניתוב). שיוך נכון בין לקוח לסוכן בעל התמחות וזמינות מתאימים מעלה מהותית את סיכויי הסגירה. מומלץ לבחון את ההתאמה ולאשר שיוך מיטבי.', 'לידים מאתרים: בחינת ניתוב להפנייה', 'בחן את התאמת הפנייה לסוכן/אזור, והעבר לאישור ניתוב מיטבי.', 'בחן את התאמת הפנייה לסוכן/אזור, והעבר לאישור ניתוב מיטבי.', 'הפנייה מועמד לניתוב מחדש. ודא שיוך לסוכן החזק והמתאים ביותר לאזור/לצורך.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־9,000 ₪ בעסקה ממוצעת.', 'שיוך לא מיטבי שורף הזדמנות אצל הלקוח.', 'הפנייה משויך לסוכן המתאים ביותר ומקודם.', 'לידים מאתרים: אתר ליד ניתוב. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הפנייה משויך לסוכן המתאים ביותר ומקודם.', null, null, null, 'אוטומציה (לידים מאתרים/אתר ליד ניתוב) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.website.website_lead_should_create_buyer', 'website', 'agent', 'high_priority', 'לידים מאתרים: אתר ליד יצירת קונה', 'זוהה אירוע בלידים מאתרים שמצדיק פעולה יזומה.', 'זוהה אירוע בלידים מאתרים שמצדיק פעולה יזומה.', 'זוהה אירוע בלידים מאתרים (אתר ליד יצירת קונה) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'לידים מאתרים: אתר ליד יצירת קונה', 'בחן את ההקשר של אתר ליד יצירת קונה בהפנייה, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של אתר ליד יצירת קונה בהפנייה, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בלידים מאתרים (אתר ליד יצירת קונה) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־9,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'לידים מאתרים: אתר ליד יצירת קונה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (לידים מאתרים/אתר ליד יצירת קונה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
