  ('lib.revenue.revenue_target_created', 'revenue', 'executive', 'quick_win', 'הכנסות ותחזית: הצנרת חדש נכנס למערכת', 'הצנרת נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הצנרת נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'מבט מנהלים: הצנרת נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון.', 'הכנסות ותחזית: הצנרת חדש נכנס למערכת', 'הצנרת חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'הצנרת חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט הצנרת חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־30,000 ₪ בעסקה ממוצעת.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'הצנרת מטופל, משויך ומקודם לצעד הבא במסלול.', 'הכנסות ותחזית: הכנסות יעד נוצר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הצנרת מטופל, משויך ומקודם לצעד הבא במסלול.', null, null, null, 'אוטומציה (הכנסות ותחזית/הכנסות יעד נוצר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.revenue.revenue_gap_detected', 'revenue', 'executive', 'high_priority', 'הכנסות ותחזית: הכנסות פער זוהה', 'זוהה אירוע בהכנסות ותחזית שמצדיק פעולה יזומה.', 'זוהה אירוע בהכנסות ותחזית שמצדיק פעולה יזומה.', 'מבט מנהלים: זוהה אירוע בהכנסות ותחזית (הכנסות פער זוהה) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'הכנסות ותחזית: הכנסות פער זוהה', 'בחן את ההקשר של הכנסות פער זוהה בהצנרת, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של הכנסות פער זוהה בהצנרת, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בהכנסות ותחזית (הכנסות פער זוהה) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־30,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'הכנסות ותחזית: הכנסות פער זוהה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (הכנסות ותחזית/הכנסות פער זוהה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.revenue.revenue_risk_critical', 'revenue', 'executive', 'deal_risk', 'הכנסות ותחזית: סיכון פעיל בהצנרת', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'מבט מנהלים: הצנרת נמצא בסיכון (הכנסות סיכון קריטי). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'הכנסות ותחזית: סיכון פעיל בהצנרת', 'טפל בשורש הסיכון בהצנרת (הכנסות סיכון קריטי) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בהצנרת (הכנסות סיכון קריטי) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'הצנרת בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־30,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'הכנסות ותחזית: הכנסות סיכון קריטי. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (הכנסות ותחזית/הכנסות סיכון קריטי) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
