  ('lib.team.management_action_created', 'team', 'manager', 'quick_win', 'צוות וניתוב: הסוכן חדש נכנס למערכת (וריאנט 4)', 'הסוכן נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הסוכן נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'לתשומת לב הניהול: הסוכן נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון. (וריאנט 4)', 'צוות וניתוב: הסוכן חדש נכנס למערכת (וריאנט 4)', 'הסוכן חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'הסוכן חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט הסוכן חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'הסוכן מטופל, משויך ומקודם לצעד הבא במסלול.', 'צוות וניתוב: ניהול פעולה נוצר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הסוכן מטופל, משויך ומקודם לצעד הבא במסלול.', null, null, null, 'אוטומציה (צוות וניתוב/ניהול פעולה נוצר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.team.team_signal_to_decision_brain', 'team', 'manager', 'high_priority', 'צוות וניתוב: צוות אות החלטה מוח', 'זוהה אירוע בצוות וניתוב שמצדיק פעולה יזומה.', 'זוהה אירוע בצוות וניתוב שמצדיק פעולה יזומה.', 'לתשומת לב הניהול: זוהה אירוע בצוות וניתוב (צוות אות החלטה מוח) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'צוות וניתוב: צוות אות החלטה מוח', 'בחן את ההקשר של צוות אות החלטה מוח בהסוכן, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של צוות אות החלטה מוח בהסוכן, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בצוות וניתוב (צוות אות החלטה מוח) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'אין השפעת הכנסה ישירה — הערך הוא תפעולי: שמירה על איכות, מהירות ודיוק התהליך.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'צוות וניתוב: צוות אות החלטה מוח. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (צוות וניתוב/צוות אות החלטה מוח) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
