  ('lib.manager.market_share_growing', 'manager', 'executive', 'high_priority', 'ניהול וצמיחת משרד: שוק נתח צומח', 'זוהה אירוע בניהול וצמיחת משרד שמצדיק פעולה יזומה.', 'זוהה אירוע בניהול וצמיחת משרד שמצדיק פעולה יזומה.', 'מבט מנהלים: זוהה אירוע בניהול וצמיחת משרד (שוק נתח צומח) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'ניהול וצמיחת משרד: שוק נתח צומח', 'בחן את ההקשר של שוק נתח צומח בהמשרד, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של שוק נתח צומח בהמשרד, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בניהול וצמיחת משרד (שוק נתח צומח) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־35,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'ניהול וצמיחת משרד: שוק נתח צומח. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (ניהול וצמיחת משרד/שוק נתח צומח) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.manager.new_city_added_by_agent', 'manager', 'executive', 'quick_win', 'ניהול וצמיחת משרד: המשרד חדש נכנס למערכת', 'המשרד נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'המשרד נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'מבט מנהלים: המשרד נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון.', 'ניהול וצמיחת משרד: המשרד חדש נכנס למערכת', 'המשרד חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'המשרד חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט המשרד חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־35,000 ₪ בעסקה ממוצעת.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'המשרד מטופל, משויך ומקודם לצעד הבא במסלול.', 'ניהול וצמיחת משרד: חדש עיר נוסף על ידי סוכן. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'המשרד מטופל, משויך ומקודם לצעד הבא במסלול.', null, null, null, 'אוטומציה (ניהול וצמיחת משרד/חדש עיר נוסף על ידי סוכן) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.manager.office_strategic_review_needed', 'manager', 'executive', 'manager_review', 'ניהול וצמיחת משרד: נדרש מבט ניהולי', 'נדרש מבט ניהולי או אישור לפני המשך.', 'נדרש מבט ניהולי או אישור לפני המשך.', 'מבט מנהלים: המשרד הגיע לרף שמצדיק מעורבות ניהולית (משרד אסטרטגי בדיקה נדרש). פעולות בעלות השפעה גבוהה דורשות אישור או ליווי כדי לאזן בין מהירות לבקרה. מומלץ להביא לבחינת מנהל לפני המשך.', 'ניהול וצמיחת משרד: נדרש מבט ניהולי', 'רכז את הנתונים הרלוונטיים להמשרד והעבר לאישור/ליווי ניהולי לפני פעולה.', 'רכז את הנתונים הרלוונטיים להמשרד והעבר לאישור/ליווי ניהולי לפני פעולה.', 'המשרד דורש החלטה ניהולית (משרד אסטרטגי בדיקה נדרש). בחן את ההקשר, אשר או הנחה את הצעד הבא.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־35,000 ₪ בעסקה ממוצעת.', 'החלטה ניהולית בזמן מונעת טעויות יקרות בפעולות רגישות.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', 'ניהול וצמיחת משרד: משרד אסטרטגי בדיקה נדרש. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', null, null, null, 'אוטומציה (ניהול וצמיחת משרד/משרד אסטרטגי בדיקה נדרש) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.')
